mapper.select:
/* SQL ID : DashboardDAO.listStdCorsData 설 명 : 수강생 메인 수강과목 부가 자료 조회 */
WITH MYCRS AS ( SELECT SBJCT_ID, STD_ID, USER_ID FROM TB_LMS_ATNDLC_SBJCT WHERE ATNDLC_STSCD = 'S' AND USER_ID = #{userId} AND SBJCT_ID IN
#{crsCreCd}
), Z AS ( SELECT X.SBJCT_ID, X.SBJCTNM, X.STD_ID, X.USER_ID, (SELECT MAX(USER_ID) FROM SBJCT_PROF WHERE SBJCT_ID = X.SBJCT_ID AND PROF_TYCD IN ('PROFESSOR','ASSOCIATE') AND RPRSYN = 'Y') AS PROF_NO, (SELECT MAX(USER_ID) FROM SBJCT_PROF WHERE SBJCT_ID = X.SBJCT_ID AND PROF_TYCD = 'ASSISTANT') AS ASSIST_NO, X.NOTICE_CNT, X.NOTICE_READ_CNT, X.QNA_CNT, X.QNA_ANS_CNT, X.SECRET_CNT, X.SECRET_ANS_CNT, X.NOTICE_BBS_ID, X.QNA_BBS_ID, X.SECRET_BBS_ID, FN_DTTM() AS NOW_DTTM FROM ( SELECT TLCC.SBJCT_ID, TLCC.SBJCTNM, MYCRS.STD_ID, MYCRS.USER_ID, SUM(CASE WHEN THBI.BBS_ID = 'NOTICE' AND TLCC.SBJCT_ID = THBR.RLTN_REF_CD AND THBA.BBS_ID = THBI.BBS_ID AND THBA.UP_ATCL_ID IS NULL AND THBA.LOCKYN = 'N' THEN 1 ELSE 0 END) AS NOTICE_CNT, SUM(CASE WHEN THBI.BBS_ID = 'NOTICE' AND TLCC.SBJCT_ID = THBR.RLTN_REF_CD AND THBA.BBS_ID = THBI.BBS_ID AND THBA.UP_ATCL_ID IS NULL AND THBA.LOCKYN = 'N' AND EXISTS ( SELECT 1 FROM TB_LMS_BBS_ATCL_INQ_RCD WHERE ATCL_ID = THBA.ATCL_ID AND USER_ID = MYCRS.USER_ID ) THEN 1 ELSE 0 END) AS NOTICE_READ_CNT, SUM(CASE WHEN THBI.BBS_ID = 'QNA' AND TLCC.SBJCT_ID = THBR.RLTN_REF_CD AND THBA.BBS_ID = THBI.BBS_ID AND THBA.UP_ATCL_ID IS NULL AND THBA.RGTR_ID = MYCRS.USER_ID THEN 1 ELSE 0 END) AS QNA_CNT, SUM(CASE WHEN THBI.BBS_ID = 'QNA' AND TLCC.SBJCT_ID = THBR.RLTN_REF_CD AND THBA.BBS_ID = THBI.BBS_ID AND THBA.UP_ATCL_ID IS NULL AND THBA.RGTR_ID = MYCRS.USER_ID AND EXISTS ( SELECT 1 FROM TB_LMS_BBS_ATCL WHERE BBS_ID = THBA.BBS_ID AND UP_ATCL_ID = THBA.ATCL_ID AND DELYN = 'N' ) THEN 1 ELSE 0 END) AS QNA_ANS_CNT, SUM(CASE WHEN THBI.BBS_ID = 'SECRET' AND TLCC.SBJCT_ID = THBR.RLTN_REF_CD AND THBA.BBS_ID = THBI.BBS_ID AND THBA.UP_ATCL_ID IS NULL AND THBA.RGTR_ID = MYCRS.USER_ID THEN 1 ELSE 0 END) AS SECRET_CNT, SUM(CASE WHEN THBI.BBS_ID = 'SECRET' AND TLCC.SBJCT_ID = THBR.RLTN_REF_CD AND THBA.BBS_ID = THBI.BBS_ID AND THBA.UP_ATCL_ID IS NULL AND THBA.RGTR_ID = MYCRS.USER_ID AND EXISTS ( SELECT 1 FROM TB_LMS_BBS_ATCL WHERE BBS_ID = THBA.BBS_ID AND UP_ATCL_ID = THBA.ATCL_ID AND DELYN = 'N' ) THEN 1 ELSE 0 END) AS SECRET_ANS_CNT, MAX(CASE WHEN THBI.BBS_ID = 'NOTICE' THEN THBI.BBS_ID END) AS NOTICE_BBS_ID, MAX(CASE WHEN THBI.BBS_ID = 'QNA' THEN THBI.BBS_ID END) AS QNA_BBS_ID, MAX(CASE WHEN THBI.BBS_ID = 'SECRET' THEN THBI.BBS_ID END) AS SECRET_BBS_ID FROM TB_LMS_SBJCT TLCC JOIN MYCRS ON TLCC.SBJCT_ID = MYCRS.SBJCT_ID LEFT JOIN TB_HOME_BBS_RLTN THBR ON THBR.RLTN_REF_CD = TLCC.SBJCT_ID AND THBR.CONTS_TYCD = 'COURSE' JOIN TB_LMS_BBS THBI ON THBI.BBS_ID = THBR.BBS_ID AND THBI.DELYN = 'N' AND THBI.USEYN = 'Y' AND THBI.SYS_BSC_PVSNYN = 'Y' LEFT JOIN TB_LMS_BBS_ATCL THBA ON THBA.BBS_ID = THBR.BBS_ID AND THBA.DELYN = 'N' AND (THBA.RSRV_USEYN = 'N' OR THBA.RSRV_DTTM <= FN_DTTM()) GROUP BY TLCC.SBJCT_ID, TLCC.SBJCTNM, MYCRS.STD_ID, MYCRS.USER_ID ) X ), ASMNT_STATS AS ( SELECT A.STD_ID, B.SBJCT_ID, COUNT(1) AS CNT FROM TB_LMS_ASMT_SBMSN A JOIN TB_LMS_ASMT B ON A.ASMT_ID = B.ASMT_ID WHERE B.DELYN = 'N' AND B.SEND_START_DTTM < FN_DTTM() AND B.ASMNT_OPEN_YN = 'Y' AND ( EXISTS ( SELECT 1 FROM TB_LMS_EXAM_STARE S JOIN TB_LMS_EXAM_BSC E ON S.EXAM_ID = E.EXAM_ID WHERE S.REEXAMYN = 'Y' AND S.DELYN = 'N' AND E.EXAM_CTGRCD = 'EXAM' AND E.EXAM_TYCD = 'EXAM' AND E.DELYN = 'N' AND E.EXAM_SBST_REF_ID = A.ASMT_ID AND S.STD_ID = A.STD_ID ) OR NOT EXISTS ( SELECT 1 FROM TB_LMS_EXAM_BSC WHERE EXAM_CTGRCD = 'EXAM' AND EXAM_TYCD = 'EXAM' AND DELYN = 'N' AND EXAM_SBST_REF_ID = A.ASMT_ID ) ) GROUP BY A.STD_ID, B.SBJCT_ID ), FORUM_CNT_STATS AS ( SELECT FO.SBJCT_ID, COUNT(1) AS CNT FROM ( SELECT A.DSCS_ID, B.SBJCT_ID, (SELECT COUNT(1) FROM TB_LMS_EXAM_STARE S, TB_LMS_EXAM_BSC E WHERE S.REEXAMYN = 'Y' AND S.DELYN = 'N' AND S.EXAM_ID = E.EXAM_ID AND E.EXAM_CTGRCD = 'EXAM' AND E.EXAM_TYCD = 'EXAM' AND E.DELYN = 'N' AND E.EXAM_SBST_REF_ID = A.DSCS_ID) AS RECNT, (SELECT COUNT(1) FROM TB_LMS_EXAM_BSC WHERE EXAM_CTGRCD = 'EXAM' AND EXAM_TYCD = 'EXAM' AND DELYN = 'N' AND EXAM_SBST_REF_ID = A.DSCS_ID) AS INCNT FROM TB_LMS_DSCS A JOIN TB_LMS_FORUM_CRE_CRS_RLTN B ON A.DSCS_ID = B.DSCS_ID WHERE A.DELYN = 'N' AND B.DELYN = 'N' AND (TO_DATE(A.DSCS_SDTTM, 'YYYYMMDDHH24MISS') - SYSDATE) * 86400 < 0 ) FO WHERE FO.RECNT > 0 OR FO.INCNT = 0 GROUP BY FO.SBJCT_ID ), QUIZ_CNT_STATS AS ( SELECT EX.SBJCT_ID, COUNT(1) AS CNT FROM ( SELECT A.EXAM_ID, B.SBJCT_ID, (SELECT COUNT(1) FROM TB_LMS_EXAM_STARE S, TB_LMS_EXAM_BSC E WHERE S.REEXAMYN = 'Y' AND S.DELYN = 'N' AND S.EXAM_ID = E.EXAM_ID AND E.EXAM_CTGRCD = 'EXAM' AND E.EXAM_TYCD = 'EXAM' AND E.DELYN = 'N' AND E.EXAM_SBST_REF_ID = A.EXAM_ID) AS RECNT, (SELECT COUNT(1) FROM TB_LMS_EXAM_BSC WHERE EXAM_CTGRCD = 'EXAM' AND EXAM_TYCD = 'EXAM' AND DELYN = 'N' AND EXAM_SBST_REF_ID = A.EXAM_ID) AS INCNT FROM TB_LMS_EXAM_BSC A JOIN TB_LMS_EXAM_CRE_CRS_RLTN B ON A.EXAM_ID = B.EXAM_ID WHERE A.EXAM_CTGRCD = 'QUIZ' AND A.DELYN = 'N' AND A.USEYN = 'Y' AND A.EXAM_SDTTM < FN_DTTM() AND A.EXAM_QSTNS_CMPTNYN IN ('Y', 'M') AND B.DELYN = 'N' ) EX WHERE EX.RECNT > 0 OR EX.INCNT = 0 GROUP BY EX.SBJCT_ID ), QUIZ_ANS_STATS AS ( SELECT Z.SBJCT_ID, Z.USER_ID, COUNT(1) AS QUIZ_ANS_CNT FROM TB_LMS_EXAM_STARE A JOIN TB_LMS_ATNDLC_SBJCT B ON A.STD_ID = B.STD_ID JOIN ( SELECT DISTINCT SBJCT_ID, USER_ID, STD_ID FROM Z ) Z ON B.USER_ID = Z.USER_ID WHERE A.DELYN = 'N' AND (A.STARE_CNT > 0 OR (TO_DATE(A.SDTTM, 'YYYYMMDDHH24MISS') + NUMTODSINTERVAL( (SELECT TKEXAM_MNTS FROM TB_LMS_EXAM_BSC WHERE EXAM_ID = A.EXAM_ID), 'MINUTE') < SYSDATE)) AND A.EXAM_ID IN ( SELECT AA.EXAM_ID FROM TB_LMS_EXAM_BSC AA JOIN TB_LMS_EXAM_CRE_CRS_RLTN BB ON AA.EXAM_ID = BB.EXAM_ID WHERE AA.EXAM_CTGRCD = 'QUIZ' AND AA.DELYN = 'N' AND AA.USEYN = 'Y' AND BB.DELYN = 'N' AND AA.EXAM_SDTTM < FN_DTTM() AND BB.SBJCT_ID = Z.SBJCT_ID AND AA.EXAM_QSTNS_CMPTNYN IN ('Y', 'M') ) GROUP BY Z.SBJCT_ID, Z.USER_ID ), RESCH_STATS AS ( SELECT B.SBJCT_ID, COUNT(1) AS RESCH_CNT FROM TB_LMS_SRVY A JOIN TB_LMS_RESCH_CRE_CRS_RLTN B ON A.SRVY_ID = B.SRVY_ID WHERE A.DELYN = 'N' AND A.USEYN = 'Y' AND A.SRVY_SDTTM < FN_DTTM() AND A.SRVY_TMPLTYN = 'N' AND A.SRVY_QSTNS_CMPTNYN = 'Y' AND B.DELYN = 'N' GROUP BY B.SBJCT_ID ), RESCH_ANS_STATS AS ( SELECT B.SBJCT_ID, COUNT(1) AS RESCH_ANS_CNT FROM TB_LMS_SRVY A JOIN TB_LMS_RESCH_CRE_CRS_RLTN B ON A.SRVY_ID = B.SRVY_ID JOIN TB_LMS_SRVY_PTCP C ON A.SRVY_ID = C.SRVY_ID WHERE C.STD_ID IN (SELECT STD_ID FROM Z) AND EXISTS ( SELECT 1 FROM TB_LMS_SRVY_RSPNS RA WHERE RA.USER_ID = C.USER_ID AND RA.SRVY_ID = C.SRVY_ID ) AND A.DELYN = 'N' AND A.USEYN = 'Y' AND A.SRVY_SDTTM < FN_DTTM() AND A.SRVY_TMPLTYN = 'N' AND A.SRVY_QSTNS_CMPTNYN = 'Y' AND B.DELYN = 'N' AND B.SBJCT_ID IN (SELECT SBJCT_ID FROM Z) GROUP BY B.SBJCT_ID ), EXAM_ANS_STATS AS ( SELECT Z.SBJCT_ID, Z.USER_ID, COUNT(1) AS EXAM_ANS_CNT FROM TB_LMS_EXAM_STARE A JOIN TB_LMS_ATNDLC_SBJCT B ON A.STD_ID = B.STD_ID JOIN ( SELECT DISTINCT SBJCT_ID, USER_ID, STD_ID FROM Z ) Z ON B.USER_ID = Z.USER_ID WHERE A.DELYN = 'N' AND A.STARE_CNT > 0 AND A.EXAM_ID IN ( SELECT AA.EXAM_ID FROM TB_LMS_EXAM_BSC AA JOIN TB_LMS_EXAM_CRE_CRS_RLTN BB ON AA.EXAM_ID = BB.EXAM_ID WHERE AA.EXAM_CTGRCD = 'EXAM' AND AA.DELYN = 'N' AND AA.USEYN = 'Y' AND AA.EXAM_SDTTM < FN_DTTM() AND AA.TKEXAM_TYCD IN ('M', 'L') AND BB.DELYN = 'N' AND BB.SBJCT_ID = Z.SBJCT_ID ) GROUP BY Z.SBJCT_ID, Z.USER_ID ), ALWAYS_EXAM_STATS AS ( SELECT B.SBJCT_ID, COUNT(1) AS ALWAYS_EXAM_CNT FROM TB_LMS_EXAM_BSC A JOIN TB_LMS_EXAM_CRE_CRS_RLTN B ON A.EXAM_ID = B.EXAM_ID AND B.DELYN = 'N' WHERE A.DELYN = 'N' AND A.USEYN = 'Y' AND A.EXAM_CTGRCD = 'EXAM' AND A.EXAM_QSTNS_CMPTNYN = 'Y' AND A.TKEXAM_TYCD = 'A' AND A.EXAM_SDTTM < FN_DTTM() GROUP BY B.SBJCT_ID ), ALWAYS_EXAM_ANS_STATS AS ( SELECT Z.SBJCT_ID, Z.USER_ID, COUNT(1) AS ALWAYS_EXAM_ANS_CNT FROM TB_LMS_EXAM_BSC A JOIN TB_LMS_EXAM_CRE_CRS_RLTN B ON A.EXAM_ID = B.EXAM_ID AND B.DELYN = 'N' JOIN TB_LMS_EXAM_STARE C ON A.EXAM_ID = C.EXAM_ID AND C.DELYN = 'N' JOIN ( SELECT DISTINCT SBJCT_ID, USER_ID, STD_ID FROM Z ) Z ON C.STD_ID IN (SELECT STD_ID FROM Z) AND Z.USER_ID = (SELECT USER_ID FROM TB_LMS_ATNDLC_SBJCT WHERE STD_ID = C.STD_ID) WHERE A.DELYN = 'N' AND A.USEYN = 'Y' AND A.EXAM_CTGRCD = 'EXAM' AND A.EXAM_QSTNS_CMPTNYN = 'Y' AND A.TKEXAM_TYCD = 'A' AND A.EXAM_SDTTM < FN_DTTM() GROUP BY Z.SBJCT_ID, Z.USER_ID ), SEMINAR_STATS AS ( SELECT SBJCT_ID, COUNT(1) AS SEMINAR_CNT FROM TB_LMS_SMNR WHERE DELYN = 'N' AND SMNR_SDTTM < FN_DTTM() GROUP BY SBJCT_ID ), SEMINAR_ANS_STATS AS ( SELECT A.SBJCT_ID, NVL(SUM(CASE WHEN B.ATND_STSCD IN ('ATTEND', 'LATE') THEN 1 ELSE 0 END), 0) AS SEMINAR_ANS_CNT FROM TB_LMS_SMNR A JOIN TB_LMS_SMNR_ATND B ON A.SMNR_ID = B.SMNR_ID WHERE A.DELYN = 'N' AND A.SMNR_SDTTM < FN_DTTM() GROUP BY A.SBJCT_ID )
SELECT Z.*, NVL(AST.CNT, 0) AS ASMNT_CNT, NVL(FCS.CNT, 0) AS FORUM_CNT, NVL(QCS.CNT, 0) AS QUIZ_CNT, NVL(QAS.QUIZ_ANS_CNT, 0) AS QUIZ_ANS_CNT, NVL(RS.RESCH_CNT, 0) AS RESCH_CNT, NVL(RAS.RESCH_ANS_CNT, 0) AS RESCH_ANS_CNT, NVL(EAS.EXAM_ANS_CNT, 0) AS EXAM_ANS_CNT, NVL(AES.ALWAYS_EXAM_CNT, 0) AS ALWAYS_EXAM_CNT, NVL(AEAS.ALWAYS_EXAM_ANS_CNT, 0) AS ALWAYS_EXAM_ANS_CNT, NVL(SS.SEMINAR_CNT, 0) AS SEMINAR_CNT, NVL(SAS.SEMINAR_ANS_CNT, 0) AS SEMINAR_ANS_CNT, (SELECT COUNT(1) FROM TB_LMS_ASMT_SBMSN A, TB_LMS_ASMT B, TB_LMS_ATNDLC_SBJCT C WHERE A.ASMT_ID = B.ASMT_ID AND UPPER(A.SBMSN_STSCD) IN ('SUBMIT','RE','LATE') AND A.STD_ID = C.STD_ID AND B.DELYN = 'N' AND B.SEND_START_DTTM < Z.NOW_DTTM AND C.SBJCT_ID = B.SBJCT_ID AND C.USER_ID = Z.USER_ID AND B.SBJCT_ID = Z.SBJCT_ID) AS ASMNT_SBMT_CNT, (SELECT COUNT(1) FROM TB_LMS_DSCS_ATCL WHERE RGTR_ID = Z.USER_ID AND DELYN = 'N' AND DSCS_ID IN ( SELECT A.DSCS_ID FROM TB_LMS_DSCS A, TB_LMS_FORUM_CRE_CRS_RLTN B WHERE A.DSCS_ID = B.DSCS_ID AND A.DELYN = 'N' AND B.DELYN = 'N' AND B.SBJCT_ID = Z.SBJCT_ID AND (TO_DATE(A.DSCS_SDTTM, 'YYYYMMDDHH24MISS') - SYSDATE) * 86400 < 0)) AS FORUM_ANS_CNT, (SELECT COUNT(1) FROM TB_LMS_EXAM_BSC A, TB_LMS_EXAM_CRE_CRS_RLTN B WHERE A.EXAM_ID = B.EXAM_ID AND A.DELYN = 'N' AND A.USEYN = 'Y' AND A.EXAM_CTGRCD = 'EXAM' AND A.EXAM_SDTTM < Z.NOW_DTTM AND A.TKEXAM_TYCD IN ('M','L') AND B.DELYN = 'N' AND B.SBJCT_ID = Z.SBJCT_ID) AS EXAM_CNT FROM Z LEFT JOIN ASMNT_STATS AST ON AST.STD_ID = Z.STD_ID AND AST.SBJCT_ID = Z.SBJCT_ID LEFT JOIN FORUM_CNT_STATS FCS ON FCS.SBJCT_ID = Z.SBJCT_ID LEFT JOIN QUIZ_CNT_STATS QCS ON QCS.SBJCT_ID = Z.SBJCT_ID LEFT JOIN ASMNT_STATS AST ON AST.STD_ID = Z.STD_ID AND AST.SBJCT_ID = Z.SBJCT_ID LEFT JOIN FORUM_CNT_STATS FCS ON FCS.SBJCT_ID = Z.SBJCT_ID LEFT JOIN QUIZ_ANS_STATS QAS ON QAS.SBJCT_ID = Z.SBJCT_ID AND QAS.USER_ID = Z.USER_ID LEFT JOIN RESCH_STATS RS ON RS.SBJCT_ID = Z.SBJCT_ID LEFT JOIN RESCH_ANS_STATS RAS ON RAS.SBJCT_ID = Z.SBJCT_ID LEFT JOIN EXAM_ANS_STATS EAS ON EAS.SBJCT_ID = Z.SBJCT_ID AND EAS.USER_ID = Z.USER_ID LEFT JOIN ALWAYS_EXAM_STATS AES ON AES.SBJCT_ID = Z.SBJCT_ID LEFT JOIN ALWAYS_EXAM_ANS_STATS AEAS ON AEAS.SBJCT_ID = Z.SBJCT_ID AND AEAS.USER_ID = Z.USER_ID LEFT JOIN SEMINAR_STATS SS ON SS.SBJCT_ID = Z.SBJCT_ID LEFT JOIN SEMINAR_ANS_STATS SAS ON SAS.SBJCT_ID = Z.SBJCT_ID

/* SQL ID : DashboardDAO.listCorExamData 설 명 : 수강생 메인 시험정보 조회 */ SELECT B.SBJCT_ID , A.EXAM_ID , A.EXAM_TYCD , CASE WHEN A.EXAM_TYCD = 'EXAM' THEN '실시간 시험' WHEN A.EXAM_TYCD = 'ETC' THEN '기타' WHEN A.EXAM_TYCD = 'ASMNT' THEN '과제' WHEN A.EXAM_TYCD = 'FORUM' THEN '토론' WHEN A.EXAM_TYCD = 'QUIZ' THEN '퀴즈' END AS EXAM_TYPE_NM , A.EXAM_TTL , A.TKEXAM_TYCD , A.TKEXAM_MNTS , A.EXAM_SDTTM , A.EXAM_EDTTM , TO_CHAR(TO_DATE(A.EXAM_SDTTM, 'YYYYMMDDHH24MISS'), 'YYYY.MM.DD HH24:MI') AS SDTTM , TO_CHAR(TO_DATE(A.EXAM_EDTTM, 'YYYYMMDDHH24MISS'), 'YYYY.MM.DD HH24:MI') AS EDTTM , A.MRK_OYN , A.EXAMPPR_OYN , A.EXAM_SBST_REF_ID , TO_CHAR(TO_DATE( CASE WHEN A.EXAM_TYCD = 'QUIZ' THEN (SELECT EXAM_SDTTM FROM TB_LMS_EXAM_BSC WHERE EXAM_ID = A.EXAM_SBST_REF_ID) WHEN A.EXAM_TYCD = 'ASMNT' THEN (SELECT SEND_START_DTTM FROM TB_LMS_ASMT WHERE ASMT_ID = A.EXAM_SBST_REF_ID) WHEN A.EXAM_TYCD = 'FORUM' THEN (SELECT DSCS_SDTTM FROM TB_LMS_DSCS WHERE DSCS_ID = A.EXAM_SBST_REF_ID) END, 'YYYYMMDDHH24MISS' ), 'YYYY.MM.DD HH24:MI' ) AS insStartDttm , TO_CHAR(TO_DATE( CASE WHEN A.EXAM_TYCD = 'QUIZ' THEN (SELECT EXAM_EDTTM FROM TB_LMS_EXAM_BSC WHERE EXAM_ID = A.EXAM_SBST_REF_ID) WHEN A.EXAM_TYCD = 'ASMNT' THEN (SELECT SEND_END_DTTM FROM TB_LMS_ASMT WHERE ASMT_ID = A.EXAM_SBST_REF_ID) WHEN A.EXAM_TYCD = 'FORUM' THEN (SELECT DSCS_EDTTM FROM TB_LMS_DSCS WHERE DSCS_ID = A.EXAM_SBST_REF_ID) END, 'YYYYMMDDHH24MISS' ), 'YYYY.MM.DD HH24:MI' ) AS insEndDttm , NVL(( SELECT MRK_RFLTRT FROM TB_LMS_STD_SCORE_ITEM_CONF WHERE SBJCT_ID = B.SBJCT_ID AND MRK_TYCD = CASE WHEN A.TKEXAM_TYCD = 'M' THEN 'MIDDLE_TEST' WHEN A.TKEXAM_TYCD = 'L' THEN 'LAST_TEST' END ), 0) AS MRK_RFLTRT FROM TB_LMS_EXAM_BSC A, TB_LMS_EXAM_CRE_CRS_RLTN B WHERE 1 = 1 AND A.EXAM_ID = B.EXAM_ID AND (A.TKEXAM_TYCD = 'M' OR A.TKEXAM_TYCD = 'L') AND A.DELYN = 'N' -- AND A.EXAM_TYCD = 'EXAM' AND A.EXAM_CTGRCD = 'EXAM' AND B.SBJCT_ID IN
#{crsCreCd}
ORDER BY A.TKEXAM_TYCD, A.EXAM_SDTTM DESC

/* SQL ID : DashboardDAO.listLessonSchedule 설 명 : 수강생 강의 주차 목록 조회 */ SELECT LCTR_SCHDL_ID , SBJCT_ID , LCTR_SCHDLNM , LCTR_SCHDL_SEQ , IF(DATEDIFF(NOW(),STR_TO_DATE(LCTR_SYMD,'%Y%m%d')) < 0, 'N', 'Y') START_DT_YN , IF(DATEDIFF(NOW(),STR_TO_DATE(LCTR_EYMD,'%Y%m%d')) < 0, 'N', 'Y') END_DT_YN FROM TB_LMS_SBJCT_LCTR_SCHDL WHERE 1 = 1 AND DELYN = 'N' /* AND OYN = 'Y' */ AND LCTR_TYCD = 'ONLINE' AND SBJCT_ID IN
#{crsCreCd}
ORDER BY SBJCT_ID, LCTR_SCHDL_SEQ

/* SQL ID : DashboardDAO.listLessonStudyState 설 명 : 수강생 강의 주차 학습상태 목록 조회 */ SELECT A.LCTR_SCHDL_ID , B.STD_ID , B.USER_ID , (SELECT ATNDLC_STSCD FROM TB_LMS_LESSON_STUDY_STATE WHERE LCTR_SCHDL_ID = A.LCTR_SCHDL_ID AND STD_ID = B.STD_ID) AS ATNDLC_STSCD FROM TB_LMS_SBJCT_LCTR_SCHDL A JOIN TB_LMS_ATNDLC_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND B.ATNDLC_STSCD = 'S' AND B.USER_ID = #{userId} JOIN TB_LMS_SBJCT C ON B.SBJCT_ID = C.SBJCT_ID AND C.DELYN = 'N' WHERE A.DELYN = 'N' AND A.SBJCT_ID IN
#{crsCreCd}
AND FN_DT() >= NVL(A.LCTR_RCG_SYMD, A.LCTR_SYMD) AND (B.AUDITYN = 'N' OR (B.AUDITYN = 'Y' AND B.ATNDLC_ABNDYN = 'N' AND C.UNIV_GBNCD IN ('3', '4')))

/* SQL ID : DashboardDAO.listProfCorsData 설 명 : 교수 메인 수강과목 부가 자료 조회 */
SELECT A.SBJCT_ID , A.SBJCTNM , A.DVCLAS_NO , TCH.USER_ID AS PROF_NO , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = TCH.USER_ID) AS PROF_NM , ( SELECT COUNT(1) FROM TB_LMS_ATNDLC_SBJCT AA JOIN TB_LMS_USER_ACNT BB ON AA.USER_ID = BB.USER_ID AND BB.ACNT_STSCD = 'U' WHERE AA.SBJCT_ID = A.SBJCT_ID AND AA.ATNDLC_STSCD = 'S' AND AA.AUDITYN = 'N' ) AS STD_CNT , ( SELECT COUNT(1) FROM TB_LMS_ATNDLC_SBJCT AA JOIN TB_LMS_USER_ACNT BB ON AA.USER_ID = BB.USER_ID AND BB.ACNT_STSCD = 'U' WHERE AA.SBJCT_ID = A.SBJCT_ID AND AA.ATNDLC_STSCD = 'S' AND AA.AUDITYN = 'Y' ) AS AUDIT_CNT FROM TB_LMS_SBJCT A LEFT JOIN SBJCT_PROF TCH ON A.SBJCT_ID = TCH.SBJCT_ID AND TCH.RPRSYN = 'Y' AND TCH.PROF_TYCD = 'PROFESSOR' WHERE A.SBJCT_ID IN
#{crsCreCd}
SELECT Z.SBJCT_ID , Z.SBJCTNM , Z.NOTICE_CNT , Z.QNA_CNT , Z.QNA_ANS_CNT , Z.SECRET_CNT , Z.SECRET_ANS_CNT , NVL(Z.PROF_NO, '-') AS PROF_NO , (CASE WHEN Z.PROF_NO IS NULL THEN '-' ELSE (SELECT NVL(USERNM, '-') FROM TB_LMS_USR WHERE USER_ID = Z.PROF_NO) END) AS PROF_NM , NVL(Z.ASSIST_NO, '-') AS ASSIST_NO , (CASE WHEN Z.ASSIST_NO IS NULL THEN '-' ELSE (SELECT NVL(USERNM, '-') FROM TB_LMS_USR WHERE USER_ID = Z.ASSIST_NO) END) AS ASSIST_NM , (CASE WHEN Z.ASSIST_NO IS NULL THEN '-' ELSE (SELECT NVL(OFCE_TELNO, '-') FROM TB_LMS_USR WHERE USER_ID = Z.ASSIST_NO) END) AS ASSIST_TEL , (SELECT COUNT(1) FROM TB_LMS_ATNDLC_SBJCT A JOIN TB_LMS_USER_ACNT J ON A.USER_ID = J.USER_ID AND J.ACNT_STSCD = 'U' WHERE A.SBJCT_ID = Z.SBJCT_ID AND A.ATNDLC_STSCD = 'S' AND A.AUDITYN = 'N') AS STD_CNT , (SELECT COUNT(1) FROM TB_LMS_ATNDLC_SBJCT A WHERE A.SBJCT_ID = Z.SBJCT_ID AND A.ATNDLC_STSCD = 'S' AND A.AUDITYN = 'Y') AUDIT_CNT , (SELECT COUNT(1) FROM TB_LMS_ASMT A WHERE A.DELYN = 'N' AND A.SBJCT_ID = Z.SBJCT_ID) AS ASMNT_CNT , (SELECT COUNT(1) FROM TB_LMS_ASMT A JOIN TB_LMS_ASMT_SBMSN B ON A.ASMT_ID = B.ASMT_ID AND B.DELYN = 'N' AND B.SBMSN_STSCD IN ('SUBMIT', 'RE', 'LATE') JOIN TB_LMS_ATNDLC_SBJCT C ON A.SBJCT_ID = C.SBJCT_ID AND B.STD_ID = C.STD_ID AND C.ATNDLC_STSCD = 'S' AND C.AUDITYN = 'N' WHERE A.DELYN = 'N' AND A.SBJCT_ID = Z.SBJCT_ID AND ( (A.ASMT_CTGRCD = 'SUBS' AND EXISTS (SELECT 1 FROM TB_LMS_EXAM_STARE WHERE STD_ID = B.STD_ID AND DELYN = 'N' AND REEXAMYN = 'Y' AND EXAM_ID = (SELECT EXAM_ID FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = A.ASMT_ID))) OR ( A.ASMT_CTGRCD <> 'SUBS' AND EXISTS (SELECT 1 FROM DUAL) ) ) ) AS ASMNT_SBMT_CNT , (SELECT COUNT(1) FROM TB_LMS_ASMT A JOIN TB_LMS_ASMT_SBMSN B ON A.ASMT_ID = B.ASMT_ID AND B.DELYN = 'N' AND B.SBMSN_STSCD IN ('SUBMIT', 'RE', 'LATE') AND B.EVLYN = 'Y' JOIN TB_LMS_ATNDLC_SBJCT C ON A.SBJCT_ID = C.SBJCT_ID AND B.STD_ID = C.STD_ID AND C.ATNDLC_STSCD = 'S' AND C.AUDITYN = 'N' WHERE A.DELYN = 'N' AND A.SBJCT_ID = Z.SBJCT_ID AND ( (A.ASMT_CTGRCD = 'SUBS' AND EXISTS (SELECT 1 FROM TB_LMS_EXAM_STARE WHERE STD_ID = B.STD_ID AND DELYN = 'N' AND REEXAMYN = 'Y' AND EXAM_ID = (SELECT EXAM_ID FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = A.ASMT_ID))) OR ( A.ASMT_CTGRCD <> 'SUBS' AND EXISTS (SELECT 1 FROM DUAL) ) ) ) AS ASMNT_EVAL_CNT , (SELECT COUNT(1) FROM TB_LMS_DSCS A WHERE A.DELYN = 'N' AND A.SBJCT_ID = Z.SBJCT_ID) AS FORUM_CNT , (SELECT COUNT(1) FROM TB_LMS_DSCS A JOIN TB_LMS_ATNDLC_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND B.ATNDLC_STSCD = 'S' AND B.AUDITYN = 'N' WHERE A.DELYN = 'N' AND EXISTS (SELECT 1 FROM TB_LMS_DSCS_ATCL WHERE DSCS_ID = A.DSCS_ID AND STD_ID = B.STD_ID AND DELYN = 'N') AND ( (A.DSCS_TYCD = 'SUBS' AND EXISTS (SELECT 1 FROM TB_LMS_EXAM_STARE WHERE STD_ID = B.STD_ID AND DELYN = 'N' AND REEXAMYN = 'Y' AND EXAM_ID = (SELECT EXAM_ID FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = A.DSCS_ID))) OR ( A.DSCS_TYCD <> 'SUBS' AND EXISTS (SELECT 1 FROM DUAL) ) ) AND A.SBJCT_ID = Z.SBJCT_ID) AS FORUM_ANS_CNT , (SELECT COUNT(1) FROM TB_LMS_DSCS A JOIN TB_LMS_ATNDLC_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND B.ATNDLC_STSCD = 'S' AND B.AUDITYN = 'N' JOIN TB_LMS_DSCS_PTCP C ON A.DSCS_ID = C.DSCS_ID AND B.STD_ID = C.STD_ID AND C.DELYN = 'N' AND C.EVLYN = 'Y' AND C.SCR IS NOT NULL WHERE A.DELYN = 'N' AND EXISTS (SELECT 1 FROM TB_LMS_DSCS_ATCL WHERE DSCS_ID = A.DSCS_ID AND STD_ID = B.STD_ID AND DELYN = 'N') AND ( (A.DSCS_TYCD = 'SUBS' AND EXISTS (SELECT 1 FROM TB_LMS_EXAM_STARE WHERE STD_ID = B.STD_ID AND DELYN = 'N' AND REEXAMYN = 'Y' AND EXAM_ID = (SELECT EXAM_ID FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = A.DSCS_ID))) OR ( A.DSCS_TYCD <> 'SUBS' AND EXISTS (SELECT 1 FROM DUAL) ) ) AND A.SBJCT_ID = Z.SBJCT_ID) AS FORUM_EVAL_CNT , (SELECT COUNT(1) FROM TB_LMS_EXAM_BSC A, TB_LMS_EXAM_CRE_CRS_RLTN B WHERE A.EXAM_CTGRCD = 'QUIZ' AND A.DELYN = 'N' AND A.USEYN = 'Y' AND A.EXAM_ID = B.EXAM_ID AND B.DELYN = 'N' AND B.SBJCT_ID = Z.SBJCT_ID) QUIZ_CNT , (SELECT COUNT(1) FROM TB_LMS_EXAM_STARE S, TB_LMS_EXAM_BSC A, TB_LMS_EXAM_CRE_CRS_RLTN B WHERE S.EXAM_ID = A.EXAM_ID AND S.DELYN = 'N' AND S.SDTTM IS NOT NULL AND A.EXAM_CTGRCD = 'QUIZ' AND A.DELYN = 'N' AND A.USEYN = 'Y' AND A.EXAM_ID = B.EXAM_ID AND B.DELYN = 'N' AND B.SBJCT_ID = Z.SBJCT_ID AND A.EXAM_QSTNS_CMPTNYN IN ('Y', 'M') AND ( (A.EXAM_TYCD = 'SUBS' AND EXISTS (SELECT 1 FROM TB_LMS_EXAM_STARE WHERE STD_ID = S.STD_ID AND DELYN = 'N' AND REEXAMYN = 'Y' AND EXAM_ID = (SELECT EXAM_ID FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = A.EXAM_ID))) OR ( A.EXAM_TYCD <> 'SUBS' AND EXISTS (SELECT 1 FROM DUAL) ) ) AND S.STD_ID IN (SELECT STD_ID FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = Z.SBJCT_ID AND ATNDLC_STSCD = 'S' AND AUDITYN = 'N')) QUIZ_ANS_CNT , (SELECT COUNT(1) FROM TB_LMS_EXAM_STARE S, TB_LMS_EXAM_BSC A, TB_LMS_EXAM_CRE_CRS_RLTN B WHERE S.EXAM_ID = A.EXAM_ID AND S.DELYN = 'N' AND S.SDTTM IS NOT NULL AND S.EVLYN = 'Y' AND A.EXAM_CTGRCD = 'QUIZ' AND A.DELYN = 'N' AND A.USEYN = 'Y' AND A.EXAM_ID = B.EXAM_ID AND B.DELYN = 'N' AND B.SBJCT_ID = Z.SBJCT_ID AND A.EXAM_QSTNS_CMPTNYN IN ('Y', 'M') AND ( (A.EXAM_TYCD = 'SUBS' AND EXISTS (SELECT 1 FROM TB_LMS_EXAM_STARE WHERE STD_ID = S.STD_ID AND DELYN = 'N' AND REEXAMYN = 'Y' AND EXAM_ID = (SELECT EXAM_ID FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = A.EXAM_ID))) OR ( A.EXAM_TYCD <> 'SUBS' AND EXISTS (SELECT 1 FROM DUAL) ) ) AND S.STD_ID IN (SELECT STD_ID FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = Z.SBJCT_ID AND ATNDLC_STSCD = 'S' AND AUDITYN = 'N')) QUIZ_EVAL_CNT , (SELECT COUNT(1) FROM TB_LMS_SRVY A, TB_LMS_RESCH_CRE_CRS_RLTN B WHERE A.DELYN = 'N' AND A.USEYN = 'Y' AND A.SRVY_ID = B.SRVY_ID AND B.DELYN = 'N' AND B.SBJCT_ID = Z.SBJCT_ID) AS RESCH_CNT , (SELECT COUNT(1) FROM TB_LMS_EXAM_BSC A, TB_LMS_EXAM_CRE_CRS_RLTN B WHERE A.EXAM_ID = B.EXAM_ID AND A.DELYN = 'N' AND A.EXAM_CTGRCD = 'EXAM' AND B.DELYN = 'N' AND B.SBJCT_ID = Z.SBJCT_ID) AS EXAM_CNT , (SELECT COUNT(1) FROM TB_LMS_EXAM_STARE S, TB_LMS_EXAM_BSC A, TB_LMS_EXAM_CRE_CRS_RLTN B WHERE S.EXAM_ID = A.EXAM_ID AND S.DELYN = 'N' AND S.SDTTM IS NOT NULL AND S.EDTTM IS NOT NULL AND A.EXAM_CTGRCD = 'EXAM' AND A.DELYN = 'N' AND A.USEYN = 'Y' AND A.EXAM_ID = B.EXAM_ID AND B.DELYN = 'N' AND B.SBJCT_ID = Z.SBJCT_ID) EXAM_ANS_CNT , (SELECT COUNT(1) FROM TB_LMS_EXAM_STARE S, TB_LMS_EXAM_BSC A, TB_LMS_EXAM_CRE_CRS_RLTN B WHERE S.EXAM_ID = A.EXAM_ID AND S.DELYN = 'N' AND S.SDTTM IS NOT NULL AND S.EDTTM IS NOT NULL AND S.EVLYN = 'Y' AND A.EXAM_CTGRCD = 'EXAM' AND A.DELYN = 'N' AND A.USEYN = 'Y' AND A.EXAM_ID = B.EXAM_ID AND B.DELYN = 'N' AND B.SBJCT_ID = Z.SBJCT_ID) EXAM_EVAL_CNT , (SELECT COUNT(1) FROM TB_LMS_SMNR WHERE DELYN = 'N' AND SBJCT_ID = Z.SBJCT_ID AND SMNR_SDTTM < FN_DTTM() ) AS SEMINAR_CNT , (SELECT NVL(SUM(CASE WHEN B.ATND_STSCD IN ('ATTEND', 'LATE') THEN 1 ELSE 0 END), 0) FROM TB_LMS_SMNR A JOIN TB_LMS_SMNR_ATND B ON A.SMNR_ID = B.SMNR_ID WHERE A.DELYN = 'N' AND A.SBJCT_ID = Z.SBJCT_ID AND A.SMNR_SDTTM < FN_DTTM() ) AS SEMINAR_ANS_CNT , Z.NOTICE_BBS_ID , Z.QNA_BBS_ID , Z.SECRET_BBS_ID , Z.CRDTS , Z.TOTAL_RATE FROM (SELECT X.SBJCT_ID , X.SBJCTNM , (SELECT USER_ID FROM SBJCT_PROF TLCCTR WHERE TLCCTR.SBJCT_ID = X.SBJCT_ID AND TLCCTR.PROF_TYCD = 'PROFESSOR' AND TLCCTR.RPRSYN = 'Y' AND ROWNUM = 1) AS PROF_NO , (SELECT USER_ID FROM SBJCT_PROF TLCCTR WHERE TLCCTR.SBJCT_ID = X.SBJCT_ID AND TLCCTR.PROF_TYCD = 'ASSISTANT' AND ROWNUM = 1) AS ASSIST_NO , X.NOTICE_CNT , X.QNA_CNT , X.QNA_ANS_CNT , X.SECRET_CNT , X.SECRET_ANS_CNT , X.NOTICE_BBS_ID , X.QNA_BBS_ID , X.SECRET_BBS_ID , X.CRDTS , ( SELECT NVL(ROUND(AVG(CASE WHEN NVL(A.ATNDLC_STSCD,'NOSTUDY') IN ('COMPLETE','LATE') THEN 1 ELSE 0 END) * 100, 2), 0) FROM TB_LMS_ATNDLC_SBJCT S JOIN TB_LMS_LESSON_STUDY_STATE A ON S.USER_ID = A.USER_ID AND S.STD_ID = A.STD_ID WHERE S.ATNDLC_STSCD = 'S' AND S.SBJCT_ID = X.SBJCT_ID ) AS TOTAL_RATE FROM ( SELECT TLCC.SBJCT_ID , TLCC.SBJCTNM , SUM(CASE WHEN THBR.CONTS_TYCD = 'COURSE' AND BBS_ID = 'NOTICE' AND TLCC.SBJCT_ID = THBR.RLTN_REF_CD AND THBA.BBS_ID = THBI.BBS_ID AND THBA.UP_ATCL_ID IS NULL THEN 1 ELSE 0 END) AS NOTICE_CNT , SUM(CASE WHEN THBR.CONTS_TYCD = 'COURSE' AND BBS_ID = 'QNA' AND TLCC.SBJCT_ID = THBR.RLTN_REF_CD AND THBA.BBS_ID = THBI.BBS_ID AND THBA.UP_ATCL_ID IS NULL THEN 1 ELSE 0 END) AS QNA_CNT , SUM(CASE WHEN THBR.CONTS_TYCD = 'COURSE' AND BBS_ID = 'QNA' AND TLCC.SBJCT_ID = THBR.RLTN_REF_CD AND THBA.BBS_ID = THBI.BBS_ID AND THBA.UP_ATCL_ID IS NULL AND EXISTS(SELECT 1 FROM TB_LMS_BBS_ATCL WHERE BBS_ID = THBA.BBS_ID AND UP_ATCL_ID = THBA.ATCL_ID AND DELYN = 'N') THEN 1 ELSE 0 END) AS QNA_ANS_CNT , SUM(CASE WHEN THBR.CONTS_TYCD = 'COURSE' AND BBS_ID = 'SECRET' AND TLCC.SBJCT_ID = THBR.RLTN_REF_CD AND THBA.BBS_ID = THBI.BBS_ID AND THBA.UP_ATCL_ID IS NULL THEN 1 ELSE 0 END) AS SECRET_CNT , SUM(CASE WHEN THBR.CONTS_TYCD = 'COURSE' AND BBS_ID = 'SECRET' AND TLCC.SBJCT_ID = THBR.RLTN_REF_CD AND THBA.BBS_ID = THBI.BBS_ID AND THBA.UP_ATCL_ID IS NULL AND EXISTS(SELECT 1 FROM TB_LMS_BBS_ATCL WHERE BBS_ID = THBA.BBS_ID AND UP_ATCL_ID = THBA.ATCL_ID AND DELYN = 'N') THEN 1 ELSE 0 END) AS SECRET_ANS_CNT , MAX(CASE WHEN BBS_ID = 'NOTICE' THEN THBI.BBS_ID END) AS NOTICE_BBS_ID , MAX(CASE WHEN BBS_ID = 'QNA' THEN THBI.BBS_ID END) AS QNA_BBS_ID , MAX(CASE WHEN BBS_ID = 'SECRET' THEN THBI.BBS_ID END) AS SECRET_BBS_ID , MAX(TLCC.CRDTS) AS CRDTS FROM TB_LMS_SBJCT TLCC LEFT OUTER JOIN TB_HOME_BBS_RLTN THBR ON THBR.RLTN_REF_CD = TLCC.SBJCT_ID AND THBR.CONTS_TYCD = 'COURSE' INNER JOIN TB_LMS_BBS THBI ON THBI.BBS_ID = THBR.BBS_ID AND THBI.DELYN = 'N' AND THBI.USEYN = 'Y' AND THBI.SYS_BSC_PVSNYN = 'Y' LEFT OUTER JOIN TB_LMS_BBS_ATCL THBA ON THBA.BBS_ID = THBR.BBS_ID AND THBA.DELYN = 'N' WHERE TLCC.SBJCT_ID IN
#{crsCreCd}
GROUP BY TLCC.SBJCT_ID, TLCC.SBJCTNM ) X ) Z

/* SQL ID : DashboardDAO.dashboardStatProf 설 명 : 대시보드 현황 (교수) */ SELECT NVL(MAX(CASE WHEN GBN = 'EXAM_ABSENT' THEN CNT1 END), 0) AS EXAM_ABSENT_CNT , NVL(MAX(CASE WHEN GBN = 'EXAM_ABSENT' THEN CNT2 END), 0) AS EXAM_ABSENT_APPROVE_CNT , NVL(MAX(CASE WHEN GBN = 'EXAM_DSBL_REQ' THEN CNT1 END), 0) AS EXAM_DSBL_REQ_CNT , NVL(MAX(CASE WHEN GBN = 'EXAM_DSBL_REQ' THEN CNT2 END), 0) AS EXAM_DSBL_REQ_APPROVE_CNT , NVL(MAX(CASE WHEN GBN = 'SCORE_OBJT' THEN CNT1 END), 0) AS SCORE_OBJT_CNT , NVL(MAX(CASE WHEN GBN = 'SCORE_OBJT' THEN CNT2 END), 0) AS SCORE_OBJT_PROC_CNT , NVL(MAX(CASE WHEN GBN = 'STD_RISK' THEN CNT1 END), 0) AS STD_CNT , NVL(MAX(CASE WHEN GBN = 'STD_RISK' THEN CNT2 END), 0) AS STD_RISK_CNT FROM ( -- 결시원 SELECT Z.GBN , COUNT(Z.GBN) as CNT1 , SUM(CASE WHEN Z.APRV_STSCD IN ('APPROVE', 'COMPANION') THEN 1 ELSE 0 END) AS CNT2 FROM ( SELECT ROW_NUMBER() OVER(PARTITION BY A.SBJCT_ID, A.EXAM_ID, A.STD_ID ORDER BY A.FRST_INQ_DTTM DESC) AS RN , 'EXAM_ABSENT' AS GBN , A.APRV_STSCD FROM TB_LMS_EXAM_ABSNCE A WHERE EXISTS ( SELECT 1 FROM TB_LMS_ATNDLC_SBJCT AA JOIN TB_LMS_USER_ACNT BB ON AA.USER_ID = BB.USER_ID AND BB.ACNT_STSCD = 'U' WHERE AA.SBJCT_ID = A.SBJCT_ID AND AA.STD_ID = A.STD_ID AND AA.ATNDLC_STSCD = 'S' AND AA.AUDITYN = 'N' AND (A.APRV_STSCD = 'APPLICATE' OR A.APRV_STSCD = 'RAPPLICATE' OR A.APRV_STSCD = 'APPROVE' OR A.APRV_STSCD = 'COMPANION') ) AND A.SBJCT_ID IN (
#{item}
)) Z WHERE Z.RN = 1 GROUP BY Z.GBN -- 장애인 지원 신청 UNION ALL SELECT 'EXAM_DSBL_REQ' AS GBN , SUM(CASE WHEN C.MID_EXAM_YN = 'Y' OR C.LAST_EXAM_YN = 'Y' THEN 1 ELSE 0 END) AS CNT1 , SUM(CASE WHEN (C.MID_EXAM_YN = 'Y' AND D.MID_APPR_STAT IN('APPROVE', 'COMPANION')) OR (C.LAST_EXAM_YN = 'Y' AND D.APRV_STSCD IN('APPROVE', 'COMPANION')) THEN 1 ELSE 0 END) AS CNT2 FROM TB_LMS_USR A JOIN TB_LMS_ATNDLC_SBJCT B ON A.USER_ID = B.USER_ID AND B.ATNDLC_STSCD = 'S' AND B.AUDITYN = 'N' AND B.SBJCT_ID IN (
#{item}
) JOIN ( SELECT AA.SBJCT_ID , NVL(MAX(CASE WHEN CC.EXAM_ID IS NOT NULL THEN 'Y' ELSE NULL END), 'N') AS MID_EXAM_YN , NVL(MAX(CASE WHEN DD.EXAM_ID IS NOT NULL THEN 'Y' ELSE NULL END), 'N') AS LAST_EXAM_YN FROM TB_LMS_SBJCT AA JOIN TB_LMS_EXAM_CRE_CRS_RLTN BB ON AA.SBJCT_ID = BB.SBJCT_ID AND BB.DELYN = 'N' LEFT JOIN TB_LMS_EXAM_BSC CC ON BB.EXAM_ID = CC.EXAM_ID AND CC.DELYN = 'N' AND CC.EXAM_CTGRCD = 'EXAM' AND CC.EXAM_TYCD = 'EXAM' AND CC.TKEXAM_TYCD = 'M' AND EXISTS(SELECT 1 FROM TB_LMS_STD_SCORE_ITEM_CONF WHERE MRK_TYCD = 'MIDDLE_TEST' AND MRK_RFLTRT >0 AND SBJCT_ID = AA.SBJCT_ID) LEFT JOIN TB_LMS_EXAM_BSC DD ON BB.EXAM_ID = DD.EXAM_ID AND DD.DELYN = 'N' AND DD.EXAM_CTGRCD = 'EXAM' AND DD.EXAM_TYCD = 'EXAM' AND DD.TKEXAM_TYCD = 'L' AND EXISTS(SELECT 1 FROM TB_LMS_STD_SCORE_ITEM_CONF WHERE MRK_TYCD = 'LAST_TEST' AND MRK_RFLTRT >0 AND SBJCT_ID = AA.SBJCT_ID) WHERE AA.DELYN = 'N' AND AA.SBJCT_ID IN (
#{item}
) GROUP BY AA.SBJCT_ID ) C ON B.SBJCT_ID = C.SBJCT_ID LEFT JOIN TB_LMS_EXAM_SPRT_APLY D ON B.SBJCT_ID = D.SBJCT_ID AND B.STD_ID = D.STD_ID WHERE A.DISABLILITY_YN = 'Y' AND A.EXAM_SPRT_APLY_TYCD = 'Y' -- 이의신청 UNION ALL SELECT 'SCORE_OBJT' AS GBN , COUNT(1) AS CNT1 , NVL(SUM(CASE WHEN A.CHG_PROC_CD IS NOT NULL THEN 1 ELSE 0 END), 0) AS CNT2 FROM MRK_OBJCT_APLY A JOIN ( SELECT A.SBJCT_ID FROM TB_LMS_SBJCT A JOIN SBJCT_PROF B ON A.SBJCT_ID = B.SBJCT_ID AND B.PROF_TYCD != 'MONITORING' AND ( (B.PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y') OR B.PROF_TYCD = 'ASSISTANT' ) AND B.USER_ID = #{userId} JOIN TB_LMS_TERM_CRE_CRS_RLTN C ON A.SBJCT_ID = C.SBJCT_ID AND C.CRS_SMSTR_ID IN ( SELECT X.CRS_SMSTR_ID FROM CRS_SMSTR X WHERE (X.DGRS_YR, X.DGRS_SMSTR) IN (SELECT DGRS_YR, DGRS_SMSTR FROM TB_LMS_SYSJOB_SCHDL WHERE SYSJOB_SCHDL_TYCD IN ('00210202', '00210203') -- 성적재확인 처리일정 AND ORG_ID = 'ORG0000001' AND USEYN = 'Y' AND FN_DTTM() BETWEEN SYSJOB_SCHDL_SYMD AND SYSJOB_SCHDL_EYMD) -- 성적재확인 일정 년도 ) WHERE A.DELYN = 'N' AND A.SBJCT_TYCD = 'UNI' ) B ON A.SBJCT_ID = B.SBJCT_ID -- 이수위험 학생수 UNION ALL SELECT 'STD_RISK' , COUNT(1) AS CNT1 , COUNT(E.USER_ID) AS CNT2 FROM TB_LMS_ATNDLC_SBJCT A JOIN TB_LMS_USR B ON A.USER_ID = B.USER_ID JOIN TB_LMS_USER_ACNT C ON A.USER_ID = C.USER_ID AND C.ACNT_STSCD = 'U' JOIN TB_LMS_SBJCT D ON A.SBJCT_ID = D.SBJCT_ID LEFT JOIN TB_LMS_LRN_STOP_RISK_IDX E ON D.SBJCT_ID = E.PSTG_YR AND D.CRS_ID = E.PSTG_SMSTR AND A.USER_ID = E.USER_ID AND E.RISK_GRDCD IN ('위험', '매우위험') WHERE A.ATNDLC_STSCD = 'S' AND A.SBJCT_ID IN (
#{item}
) AND A.AUDITYN = 'N' ) A

/* SQL ID : DashboardDAO.dashboardStatStu 설 명 : 대시보드 현황 (학생) */ SELECT NVL(MAX(CASE WHEN GBN = 'EXAM_DSBL_REQ' THEN CNT1 END), 0) AS EXAM_DSBL_REQ_CNT , NVL(MAX(CASE WHEN GBN = 'EXAM_DSBL_REQ' THEN CNT2 END), 0) AS EXAM_DSBL_REQ_APPROVE_CNT , NVL(MAX(CASE WHEN GBN = 'EXAM_ABSENT' THEN CNT1 END), 0) AS EXAM_ABSENT_CNT , NVL(MAX(CASE WHEN GBN = 'EXAM_ABSENT' THEN CNT2 END), 0) AS EXAM_ABSENT_APPROVE_CNT , NVL(MAX(CASE WHEN GBN = 'SCORE_OBJT' THEN CNT1 END), 0) AS SCORE_OBJT_CNT , NVL(MAX(CASE WHEN GBN = 'SCORE_OBJT' THEN CNT2 END), 0) AS SCORE_OBJT_PROC_CNT FROM ( -- 장애인 지원 SELECT 'EXAM_DSBL_REQ' AS GBN , COUNT(1) * 2 AS CNT1 , SUM(CASE WHEN A.MID_APPR_STAT = 'APPROVE' THEN 1 ELSE 0 END) + SUM( CASE WHEN A.APRV_STSCD = 'APPROVE' THEN 1 ELSE 0 END ) AS CNT2 FROM TB_LMS_EXAM_SPRT_APLY A WHERE EXISTS ( SELECT 1 FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = A.SBJCT_ID AND STD_ID = A.STD_ID AND ATNDLC_STSCD = 'S' AND USER_ID = #{userId} ) AND A.SBJCT_ID IN (
#{item}
) -- 결시원 UNION ALL SELECT 'EXAM_ABSENT' AS GBN , COUNT(1) AS CNT1 , NVL(SUM(CASE WHEN A.APRV_STSCD = 'APPROVE' THEN 1 ELSE 0 END ), 0) AS CNT2 FROM TB_LMS_EXAM_ABSNCE A WHERE EXISTS ( SELECT 1 FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = A.SBJCT_ID AND STD_ID = A.STD_ID AND ATNDLC_STSCD = 'S' AND USER_ID = #{userId} ) AND A.SBJCT_ID IN (
#{item}
) -- 이의신청 UNION ALL SELECT 'SCORE_OBJT' AS GBN , COUNT(1) AS CNT1 , SUM(CASE WHEN A.CHG_PROC_CD IS NOT NULL THEN 1 ELSE 0 END ) AS CNT2 FROM MRK_OBJCT_APLY A WHERE EXISTS ( SELECT 1 FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = A.SBJCT_ID AND STD_ID = A.STD_ID AND ATNDLC_STSCD = 'S' AND USER_ID = #{userId} ) AND A.SBJCT_ID IN (
#{item}
) ) A

/* SQL ID : DashboardDAO.countAdminCorsData 설 명 : 관리자 메인 개설과목 카운트 */ SELECT COUNT(1) FROM ( SELECT TLTCCR.CRS_SMSTR_ID , TLCC.CRS_ID , TLCC.SBJCT_ID , TLCC.CRS_ID , TLCC.SBJCT_ID , TLCC.SBJCTNM , TLCC.DVCLAS_NO , TLCC.UNIV_CD , TLCC.DEPT_CD , SUM(IF(THBR.CONTS_TYCD = 'COURSE' AND BBS_ID = 'NOTICE' AND TLCC.SBJCT_ID = THBR.RLTN_REF_CD AND THBA.BBS_ID = THBI.BBS_ID AND THBA.UP_ATCL_ID IS NULL , 1, 0)) AS NOTICE_CNT , SUM(IF(THBR.CONTS_TYCD = 'COURSE' AND BBS_ID = 'QNA' AND TLCC.SBJCT_ID = THBR.RLTN_REF_CD AND THBA.BBS_ID = THBI.BBS_ID AND THBA.UP_ATCL_ID IS NULL , 1, 0)) AS QNA_CNT , SUM(IF(THBR.CONTS_TYCD = 'COURSE' AND BBS_ID = 'SECRET' AND TLCC.SBJCT_ID = THBR.RLTN_REF_CD AND THBA.BBS_ID = THBI.BBS_ID AND THBA.UP_ATCL_ID IS NULL , 1, 0)) AS SECRET_CNT FROM TB_LMS_SBJCT TLCC INNER JOIN TB_LMS_TERM_CRE_CRS_RLTN TLTCCR ON TLCC.SBJCT_ID = TLTCCR.SBJCT_ID AND TLCC.DELYN = 'N' AND TLCC.USEYN = 'Y' LEFT OUTER JOIN TB_HOME_BBS_RLTN THBR ON THBR.RLTN_REF_CD = TLCC.SBJCT_ID AND THBR.CONTS_TYCD = 'COURSE' JOIN TB_LMS_BBS THBI ON THBI.BBS_ID = THBR.BBS_ID AND THBI.DELYN = 'N' AND THBI.USEYN = 'Y' AND THBI.SYS_BSC_PVSNYN = 'Y' LEFT OUTER JOIN TB_LMS_BBS_ATCL THBA ON THBA.BBS_ID = THBI.BBS_ID AND THBA.DELYN = 'N' WHERE 1 = 1
AND TLTCCR.CRS_SMSTR_ID = #{termCd}
AND TLCC.DEPT_CD = #{deptCd}
AND TLCC.UNIV_CD = #{uniCd}
AND ( LOWER(TLCC.SBJCTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(TLCC.CRS_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
GROUP BY TLTCCR.CRS_SMSTR_ID, TLCC.CRS_ID, TLCC.SBJCT_ID, TLCC.SBJCTNM, TLCC.DVCLAS_NO, TLCC.UNIV_CD, TLCC.DEPT_CD ) X

/* SQL ID : DashboardDAO.listAdminCorsData 설 명 : 관리자 메인 개설과목 조회 */
SELECT Z.CRS_SMSTR_ID , Z.CRS_ID , Z.NOTICE_CNT , Z.QNA_CNT , Z.SECRET_CNT , Z.SBJCT_ID , Z.SBJCTNM , Z.DVCLAS_NO , Z.UNIV_CD , Z.DEPT_CD , Z.NOTICE_CNT , Z.QNA_CNT , Z.SECRET_CNT , (SELECT SMSTRNM FROM CRS_SMSTR WHERE CRS_SMSTR_ID = Z.CRS_SMSTR_ID) AS SMSTRNM , (SELECT DEPTNM FROM TB_HOME_USER_DEPT_CD WHERE ORG_ID = #{orgId} AND DEPT_CD = Z.DEPT_CD AND USEYN = 'Y') AS DEPTNM , (CASE WHEN Z.USER_ID IS NULL THEN '-' ELSE (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = Z.USER_ID) END) AS USERNM , NVL(Z.USER_ID, '-') AS USER_ID , (SELECT DATE_FORMAT(STR_TO_DATE(A.EXAM_SDTTM, '%Y%m%d%H%i%s'),'%Y.%m.%d %H:%i') FROM TB_LMS_EXAM_BSC A, TB_LMS_EXAM_CRE_CRS_RLTN B WHERE A.EXAM_ID = B.EXAM_ID AND A.TKEXAM_TYCD = 'M' AND A.DELYN = 'N' AND A.EXAM_TYCD = 'EXAM' AND A.EXAM_CTGRCD = 'EXAM' AND B.DELYN = 'N' AND B.SBJCT_ID = Z.SBJCT_ID) AS MIDDLE_START_DTTM , (SELECT TKEXAM_MNTS FROM TB_LMS_EXAM_BSC A, TB_LMS_EXAM_CRE_CRS_RLTN B WHERE A.EXAM_ID = B.EXAM_ID AND A.TKEXAM_TYCD = 'M' AND A.DELYN = 'N' AND A.EXAM_TYCD = 'EXAM' AND A.EXAM_CTGRCD = 'EXAM' AND B.DELYN = 'N' AND B.SBJCT_ID = Z.SBJCT_ID) AS MIDDLE_EXAM_STARE_TM , (SELECT DATE_FORMAT(STR_TO_DATE(A.EXAM_SDTTM, '%Y%m%d%H%i%s'),'%Y.%m.%d %H:%i') FROM TB_LMS_EXAM_BSC A, TB_LMS_EXAM_CRE_CRS_RLTN B WHERE A.EXAM_ID = B.EXAM_ID AND A.TKEXAM_TYCD = 'L' AND A.DELYN = 'N' AND A.EXAM_TYCD = 'EXAM' AND A.EXAM_CTGRCD = 'EXAM' AND B.DELYN = 'N' AND B.SBJCT_ID = Z.SBJCT_ID) AS LAST_START_DTTM , (SELECT TKEXAM_MNTS FROM TB_LMS_EXAM_BSC A, TB_LMS_EXAM_CRE_CRS_RLTN B WHERE A.EXAM_ID = B.EXAM_ID AND A.TKEXAM_TYCD = 'L' AND A.DELYN = 'N' AND A.EXAM_TYCD = 'EXAM' AND A.EXAM_CTGRCD = 'EXAM' AND B.DELYN = 'N' AND B.SBJCT_ID = Z.SBJCT_ID) AS LAST_EXAM_STARE_TM , (SELECT COUNT(1) FROM TB_LMS_ATNDLC_SBJCT A WHERE A.SBJCT_ID = Z.SBJCT_ID AND A.ATNDLC_STSCD = 'S' AND A.AUDITYN = 'N') STD_CNT , (SELECT COUNT(1) FROM TB_LMS_ATNDLC_SBJCT A WHERE A.SBJCT_ID = Z.SBJCT_ID AND A.ATNDLC_STSCD = 'S' AND A.AUDITYN = 'Y') AUDIT_CNT , (SELECT COUNT(1) FROM TB_LMS_ASMT_SBMSN J, TB_LMS_ASMT A WHERE J.ASMT_ID = A.ASMT_ID AND J.DELYN = 'N' AND A.DELYN = 'N' AND J.EVLYN ='Y' AND (J.SCR = 0 OR J.SCR = '0' OR J.SCR = '') AND A.SBJCT_ID = Z.SBJCT_ID) AS ASMNT_CNT , (SELECT COUNT(1) FROM TB_LMS_DSCS_PTCP J, TB_LMS_DSCS A WHERE J.DSCS_ID = A.DSCS_ID AND J.DELYN = 'N' AND A.DELYN = 'N' AND J.EVLYN ='Y' AND (J.SCR = 0 OR J.SCR = '0' OR J.SCR = '') AND A.SBJCT_ID = Z.SBJCT_ID) AS FORUM_CNT , (SELECT COUNT(1) FROM TB_LMS_EXAM_STARE S, TB_LMS_EXAM_BSC A, TB_LMS_EXAM_CRE_CRS_RLTN B WHERE S.EXAM_ID = A.EXAM_ID AND S.DELYN = 'N' AND (S.SDTTM IS NULL OR S.SDTTM = '') AND S.EVLYN = 'Y' AND A.EXAM_CTGRCD = 'QUIZ' AND A.DELYN = 'N' AND A.USEYN = 'Y' AND A.EXAM_ID = B.EXAM_ID AND B.SBJCT_ID = Z.SBJCT_ID) AS QUIZ_CNT , (SELECT COUNT(1) FROM TB_LMS_SRVY_RSPNS S, TB_LMS_SRVY A, TB_LMS_RESCH_CRE_CRS_RLTN B WHERE S.SRVY_ID = A.SRVY_ID AND A.DELYN = 'N' AND A.USEYN = 'Y' AND A.SRVY_ID = B.SRVY_ID AND B.SBJCT_ID = Z.SBJCT_ID) AS RESCH_CNT , (SELECT COUNT(1) FROM TB_LMS_SMNR_ATND J, TB_LMS_SMNR A WHERE J.SMNR_ID = A.SMNR_ID AND A.DELYN = 'N' AND A.SBJCT_ID = Z.SBJCT_ID) AS SEMINAR_CNT , (SELECT COUNT(1) FROM TB_LOG_USER_CONN_STAT A, TB_LMS_USR B WHERE A.USER_ID = B.USER_ID AND A.SBJCT_ID = Z.SBJCT_ID) AS ACCESS_CNT , (SELECT NVL(ROUND(C.TOTAL_RATE, 2),0) FROM (SELECT AVG(IF(A.ATNDLC_STSCD IN('COMPLETE', 'LATE'), 1, 0)) * 100 AS TOTAL_RATE FROM (SELECT NVL(B.ATNDLC_STSCD, 'NOSTUDY') AS ATNDLC_STSCD FROM TB_LMS_ATNDLC_SBJCT S, TB_LMS_LESSON_STUDY_STATE B WHERE S.USER_ID = B.USER_ID AND S.STD_ID = B.STD_ID AND S.ATNDLC_STSCD = 'S' AND S.ORG_ID = #{orgId} AND S.SBJCT_ID = Z.SBJCT_ID ) A ) C) AS TOTAL_RATE FROM (SELECT X.CRS_SMSTR_ID , X.CRS_ID , X.SBJCT_ID , X.SBJCTNM , X.DVCLAS_NO , X.UNIV_CD , X.DEPT_CD , (SELECT USER_ID FROM SBJCT_PROF TLCCTR WHERE TLCCTR.SBJCT_ID = X.SBJCT_ID AND (TLCCTR.PROF_TYCD = 'PROFESSOR' OR TLCCTR.PROF_TYCD = 'ASSOCIATE') AND TLCCTR.RPRSYN = 'Y') AS USER_ID , X.NOTICE_CNT , X.QNA_CNT , X.SECRET_CNT FROM ( SELECT TLTCCR.CRS_SMSTR_ID , TLCC.CRS_ID , TLCC.SBJCT_ID , TLCC.CRS_ID , TLCC.SBJCT_ID , TLCC.SBJCTNM , TLCC.DVCLAS_NO , TLCC.UNIV_CD , TLCC.DEPT_CD , SUM(IF(THBR.CONTS_TYCD = 'COURSE' AND BBS_ID = 'NOTICE' AND TLCC.SBJCT_ID = THBR.RLTN_REF_CD AND THBA.BBS_ID = THBI.BBS_ID AND THBA.UP_ATCL_ID IS NULL , 1, 0)) AS NOTICE_CNT , SUM(IF(THBR.CONTS_TYCD = 'COURSE' AND BBS_ID = 'QNA' AND TLCC.SBJCT_ID = THBR.RLTN_REF_CD AND THBA.BBS_ID = THBI.BBS_ID AND THBA.UP_ATCL_ID IS NULL , 1, 0)) AS QNA_CNT , SUM(IF(THBR.CONTS_TYCD = 'COURSE' AND BBS_ID = 'SECRET' AND TLCC.SBJCT_ID = THBR.RLTN_REF_CD AND THBA.BBS_ID = THBI.BBS_ID AND THBA.UP_ATCL_ID IS NULL , 1, 0)) AS SECRET_CNT FROM TB_LMS_SBJCT TLCC INNER JOIN TB_LMS_TERM_CRE_CRS_RLTN TLTCCR ON TLCC.SBJCT_ID = TLTCCR.SBJCT_ID AND TLCC.DELYN = 'N' AND TLCC.USEYN = 'Y' LEFT OUTER JOIN TB_HOME_BBS_RLTN THBR ON THBR.RLTN_REF_CD = TLCC.SBJCT_ID AND THBR.CONTS_TYCD = 'COURSE' JOIN TB_LMS_BBS THBI ON THBI.BBS_ID = THBR.BBS_ID AND THBI.DELYN = 'N' AND THBI.USEYN = 'Y' AND THBI.SYS_BSC_PVSNYN = 'Y' LEFT OUTER JOIN TB_LMS_BBS_ATCL THBA ON THBA.BBS_ID = THBI.BBS_ID AND THBA.DELYN = 'N' WHERE 1 = 1
AND TLTCCR.CRS_SMSTR_ID = #{termCd}
AND TLCC.DEPT_CD = #{deptCd}
AND TLCC.UNIV_CD = #{uniCd}
AND ( LOWER(TLCC.SBJCTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(TLCC.CRS_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
GROUP BY TLTCCR.CRS_SMSTR_ID, TLCC.CRS_ID, TLCC.SBJCT_ID, TLCC.SBJCTNM, TLCC.DVCLAS_NO, TLCC.UNIV_CD, TLCC.DEPT_CD ) X ORDER BY X.SBJCT_ID
) Z

/* SQL ID : DashboardDAO.selectBbsAnsStatus 설 명 : 수업운영 게시판 답변 현황 조회 */ SELECT A.QNA_NO_ANS_CNT , CASE WHEN A.QNA_SEC = 0 THEN 0 WHEN A.QNA_SEC > 3600 THEN FLOOR(A.QNA_SEC / 3600) ELSE ROUND(CEIL(A.QNA_SEC / 3600 * 10) / 10, 1) END AS QNA_HOUR , A.SECRET_NO_ANS_CNT , CASE WHEN A.SECRET_SEC = 0 THEN 0 WHEN A.SECRET_SEC > 3600 THEN FLOOR(A.SECRET_SEC / 3600) ELSE ROUND(CEIL(A.SECRET_SEC / 3600 * 10) / 10, 1) END AS SECRET_HOUR FROM ( SELECT NVL(MAX(CASE WHEN A.BBS_ID = 'QNA' THEN NO_ANS_CNT ELSE 0 END), 0) AS QNA_NO_ANS_CNT , NVL(MAX(CASE WHEN A.BBS_ID = 'QNA' THEN SEC ELSE 0 END), 0) AS QNA_SEC , NVL(MAX(CASE WHEN A.BBS_ID = 'SECRET' THEN NO_ANS_CNT ELSE 0 END), 0) AS SECRET_NO_ANS_CNT , NVL(MAX(CASE WHEN A.BBS_ID = 'SECRET' THEN SEC ELSE 0 END), 0) AS SECRET_SEC FROM ( SELECT A.BBS_ID , SUM(A.NO_ANS_CNT) AS NO_ANS_CNT , AVG(A.SEC) AS SEC FROM ( SELECT A.BBS_ID , B.ATCL_ID , SUM(CASE WHEN C.ATCL_ID IS NULL THEN 1 ELSE 0 END) AS NO_ANS_CNT , NVL((CAST(MIN(C.FRST_INQ_DTTM) AS DATE) - TO_DATE(B.FRST_INQ_DTTM, 'YYYYMMDDHH24MISS')) * 86400, 0) AS SEC FROM ( SELECT A.BBS_ID , A.BBS_ID FROM TB_LMS_BBS A JOIN TB_HOME_BBS_RLTN B ON A.BBS_ID = B.BBS_ID AND B.CONTS_TYCD = 'COURSE' AND B.RLTN_REF_CD IN
#{item}
WHERE A.DELYN = 'N' AND A.USEYN = 'Y' AND A.SYS_BSC_PVSNYN = 'Y' AND A.BBS_ID IN ('QNA', 'SECRET') ) A JOIN TB_LMS_BBS_ATCL B ON A.BBS_ID = B.BBS_ID AND B.DELYN = 'N' AND B.UP_ATCL_ID IS NULL LEFT JOIN TB_LMS_BBS_ATCL C ON B.ATCL_ID = C.UP_ATCL_ID AND C.DELYN = 'N' GROUP BY A.BBS_ID, B.ATCL_ID, B.FRST_INQ_DTTM ) A GROUP BY A.BBS_ID ) A ) A

/* SQL ID : DashboardDAO.selectOprScoreProfStatus 설 명 : 수업운영 점수 현황 (교수) */ SELECT ( SELECT SUM(A.TOT_SCR) FROM EVL_SCR A JOIN TB_LMS_SBJCT_LCTR_SCHDL B ON A.LCTR_SCHDL_ID = B.LCTR_SCHDL_ID AND B.DELYN = 'N' AND B.LCTR_SCHDL_SEQ = ( SELECT MIN(TOC_SEQ) - 1 FROM CRS_SMSTR_WKNO WHERE CRS_SMSTR_ID = #{termCd} AND FN_DT() BETWEEN SYMD AND EYMD ) AND B.SBJCT_ID IN
#{item}
JOIN TB_LMS_SBJCT C ON B.SBJCT_ID = C.SBJCT_ID AND C.GRDTN_SBJCTYN = 'N' AND C.CRS_ID NOT IN ('CSW034', 'CCE024', 'CHY164') AND C.CRS_ID NOT LIKE '%TEST%' AND C.CRS_ID NOT LIKE '%JLPT%' WHERE A.DELYN = 'N' AND A.USER_ID = #{userId} ) AS LAST_WEEK_OPR_SCORE , ( SELECT SUM(A.TOT_SCR) FROM EVL_SCR A JOIN TB_LMS_SBJCT_LCTR_SCHDL B ON A.LCTR_SCHDL_ID = B.LCTR_SCHDL_ID AND B.DELYN = 'N' AND B.SBJCT_ID IN
#{item}
JOIN TB_LMS_SBJCT C ON B.SBJCT_ID = C.SBJCT_ID AND C.GRDTN_SBJCTYN = 'N' AND C.CRS_ID NOT IN ('CSW034', 'CCE024', 'CHY164') AND C.CRS_ID NOT LIKE '%TEST%' AND C.CRS_ID NOT LIKE '%JLPT%' WHERE A.DELYN = 'N' AND A.USER_ID = #{userId} ) AS OPR_TOT_SCORE FROM DUAL

/* SQL ID : DashboardDAO.selectOprScoreAssistStatus 설 명 : 수업운영 점수 현황 (조교) */ SELECT ( SELECT SUM(A.TOT_SCR) FROM OP_EVL A JOIN TB_LMS_SBJCT_LCTR_SCHDL B ON A.LCTR_SCHDL_ID = B.LCTR_SCHDL_ID AND B.DELYN = 'N' AND B.LCTR_SCHDL_SEQ = ( SELECT MIN(TOC_SEQ) - 1 FROM CRS_SMSTR_WKNO WHERE CRS_SMSTR_ID = #{termCd} AND FN_DT() BETWEEN SYMD AND EYMD ) AND B.SBJCT_ID IN
#{item}
JOIN TB_LMS_SBJCT C ON B.SBJCT_ID = C.SBJCT_ID AND C.CRS_ID NOT LIKE '%TEST%' AND A.CRS_ID NOT LIKE '%JLPT%' WHERE A.DELYN = 'N' AND A.USER_ID = #{userId} ) AS LAST_WEEK_OPR_SCORE , ( SELECT SUM(A.TOT_SCR) FROM OP_EVL A JOIN TB_LMS_SBJCT_LCTR_SCHDL B ON A.LCTR_SCHDL_ID = B.LCTR_SCHDL_ID AND B.DELYN = 'N' AND B.SBJCT_ID IN
#{item}
JOIN TB_LMS_SBJCT C ON B.SBJCT_ID = C.SBJCT_ID AND C.CRS_ID NOT LIKE '%TEST%' WHERE A.DELYN = 'N' AND A.USER_ID = #{userId} ) AS OPR_TOT_SCORE FROM DUAL

/* SQL ID : DashboardDAO.listLessonStatusByCrs 설 명 : 관리자 메인 > 과목별 학습현황 */
SELECT ROW_NUMBER() OVER(ORDER BY A.DEPT_CD_ODR, A.CRS_ID, A.DVCLAS_NO) AS LINE_NO , A.SBJCT_ID , A.UNIV_CD , A.UNIV_GBNCD , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = #{orgId} AND CTGRCD = 'UNIV_GBNCD' AND CD = A.UNIV_GBNCD) AS UNIV_GBN_NM , A.CRS_ID , A.SBJCTNM , A.SBJCT_ID , A.CRS_ID , A.DEPTNM , A.DVCLAS_NO , A.USERNM , A.USER_ID , (SELECT MOBILE_NO FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) AS MOBILE_NO , (SELECT EMAIL FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) AS EMAIL , A.ASSIST_NO , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.ASSIST_NO) AS ASSIST_NM , (SELECT OFCE_TELNO FROM TB_LMS_USR WHERE USER_ID = A.ASSIST_NO) AS ASSIST_OFCE_TELNO , (SELECT COUNT(1) FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = A.SBJCT_ID AND ATNDLC_STSCD = 'S' AND AUDITYN = 'N') AS STD_CNT , (SELECT COUNT(1) FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = A.SBJCT_ID AND ATNDLC_STSCD = 'S' AND AUDITYN = 'Y') AS AUDIT_CNT , ( SELECT COUNT(1) FROM TB_LMS_BBS AA JOIN TB_HOME_BBS_RLTN BB ON AA.BBS_ID = BB.BBS_ID AND BB.CONTS_TYCD = 'COURSE' JOIN TB_LMS_BBS_ATCL CC ON AA.BBS_ID = CC.BBS_ID AND CC.DELYN = 'N' AND CC.LOCKYN = 'N' WHERE BB.RLTN_REF_CD = A.SBJCT_ID AND AA.DELYN = 'N' AND AA.SYS_BSC_PVSNYN = 'Y' AND AA.BBS_ID = 'NOTICE' ) AS NOTICE_CNT , ( SELECT NVL(SUM(CASE WHEN EXISTS((SELECT 1 FROM TB_LMS_BBS_ATCL WHERE BBS_ID = CC.BBS_ID AND UP_ATCL_ID = CC.ATCL_ID AND DELYN = 'N')) THEN 1 ELSE 0 END), 0) || '/' || COUNT(1) FROM TB_LMS_BBS AA JOIN TB_HOME_BBS_RLTN BB ON AA.BBS_ID = BB.BBS_ID AND BB.CONTS_TYCD = 'COURSE' JOIN TB_LMS_BBS_ATCL CC ON AA.BBS_ID = CC.BBS_ID AND CC.DELYN = 'N' AND CC.UP_ATCL_ID IS NULL WHERE BB.RLTN_REF_CD = A.SBJCT_ID AND AA.DELYN = 'N' AND AA.SYS_BSC_PVSNYN = 'Y' AND AA.BBS_ID = 'QNA' ) AS QNA_CNT , ( SELECT NVL(SUM(CASE WHEN EXISTS((SELECT 1 FROM TB_LMS_BBS_ATCL WHERE BBS_ID = CC.BBS_ID AND UP_ATCL_ID = CC.ATCL_ID AND DELYN = 'N')) THEN 1 ELSE 0 END), 0) || '/' || COUNT(1) FROM TB_LMS_BBS AA JOIN TB_HOME_BBS_RLTN BB ON AA.BBS_ID = BB.BBS_ID AND BB.CONTS_TYCD = 'COURSE' JOIN TB_LMS_BBS_ATCL CC ON AA.BBS_ID = CC.BBS_ID AND CC.DELYN = 'N' AND CC.UP_ATCL_ID IS NULL WHERE BB.RLTN_REF_CD = A.SBJCT_ID AND AA.DELYN = 'N' AND AA.SYS_BSC_PVSNYN = 'Y' AND AA.BBS_ID = 'SECRET' ) AS SECRET_CNT , ( SELECT NVL(SUM(CASE WHEN NOT EXISTS((SELECT 1 FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = AA.ASMT_ID)) AND BB.EVLYN = 'Y' THEN 1 ELSE 0 END), 0) || '/' || NVL(SUM(CASE WHEN NOT EXISTS((SELECT 1 FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = AA.ASMT_ID)) THEN 1 ELSE 0 END), 0) FROM TB_LMS_ASMT AA JOIN TB_LMS_ASMT_SBMSN BB ON AA.ASMT_ID = BB.ASMT_ID AND BB.SBMSN_STSCD IN ('SUBMIT', 'RE', 'LATE') AND BB.DELYN = 'N' WHERE AA.DELYN = 'N' AND BB.STD_ID IN (SELECT STD_ID FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = A.SBJCT_ID AND ATNDLC_STSCD = 'S' AND AUDITYN = 'N') AND AA.SBJCT_ID = A.SBJCT_ID ) AS ASMNT_CNT , ( SELECT NVL(SUM(CASE WHEN NOT EXISTS((SELECT 1 FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = AA.DSCS_ID)) AND CC.EVLYN = 'Y' AND CC.SCR IS NOT NULL THEN 1 ELSE 0 END), 0) || '/' || NVL(SUM(CASE WHEN NOT EXISTS (SELECT 1 FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = AA.DSCS_ID) AND (EXISTS (SELECT 1 FROM TB_LMS_DSCS_ATCL WHERE DSCS_ID = AA.DSCS_ID AND STD_ID = BB.STD_ID AND DELYN = 'N') OR EXISTS (SELECT 1 FROM TB_LMS_DSCS_CMNT WHERE DSCS_ID = AA.DSCS_ID AND STD_ID = BB.STD_ID AND DELYN = 'N')) THEN 1 ELSE 0 END), 0) FROM TB_LMS_DSCS AA JOIN TB_LMS_ATNDLC_SBJCT BB ON AA.SBJCT_ID = BB.SBJCT_ID AND BB.ATNDLC_STSCD = 'S' AND BB.AUDITYN = 'N' LEFT JOIN TB_LMS_DSCS_PTCP CC ON AA.DSCS_ID = CC.DSCS_ID AND BB.STD_ID = CC.STD_ID AND CC.DELYN = 'N' WHERE AA.DELYN = 'N' AND AA.SBJCT_ID = A.SBJCT_ID ) AS FORUM_CNT , ( SELECT NVL(SUM(CASE WHEN NOT EXISTS((SELECT 1 FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = AA.EXAM_ID)) AND CC.EVLYN = 'Y' THEN 1 ELSE 0 END), 0) || '/' || NVL(SUM(CASE WHEN NOT EXISTS((SELECT 1 FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = AA.EXAM_ID)) THEN 1 ELSE 0 END), 0) FROM TB_LMS_EXAM_BSC AA JOIN TB_LMS_EXAM_CRE_CRS_RLTN BB ON AA.EXAM_ID = BB.EXAM_ID AND BB.DELYN = 'N' JOIN TB_LMS_EXAM_STARE CC ON AA.EXAM_ID = CC.EXAM_ID AND CC.STARE_CNT > 0 AND CC.DELYN = 'N' WHERE BB.SBJCT_ID = A.SBJCT_ID AND CC.STD_ID IN (SELECT STD_ID FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = A.SBJCT_ID AND ATNDLC_STSCD = 'S' AND AUDITYN = 'N') AND AA.DELYN = 'N' AND AA.USEYN = 'Y' AND AA.EXAM_QSTNS_CMPTNYN IN ('Y', 'M') AND AA.EXAM_CTGRCD = 'QUIZ' AND AA.TKEXAM_TYCD = 'A' ) AS QUIZ_CNT , ( SELECT NVL(SUM(CASE WHEN CC.EVLYN = 'Y' THEN 1 ELSE 0 END), 0) || '/' || COUNT(1) FROM TB_LMS_SRVY AA JOIN TB_LMS_RESCH_CRE_CRS_RLTN BB ON AA.SRVY_ID = BB.SRVY_ID AND BB.DELYN = 'N' JOIN TB_LMS_SRVY_PTCP CC ON AA.SRVY_ID = CC.SRVY_ID AND EXISTS (SELECT 1 FROM TB_LMS_SRVY_RSPNS WHERE USER_ID = CC.USER_ID AND SRVY_ID = AA.SRVY_ID) WHERE BB.SBJCT_ID = A.SBJCT_ID AND CC.USER_ID IN (SELECT USER_ID FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = A.SBJCT_ID AND ATNDLC_STSCD = 'S' AND AUDITYN = 'N') AND AA.DELYN = 'N' AND AA.USEYN = 'Y' AND AA.SRVY_QSTNS_CMPTNYN = 'Y' AND AA.SRVY_TMPLTYN = 'N' ) AS RESCH_CNT , ( SELECT NVL(SUM(CASE WHEN CC.EVLYN = 'Y' THEN 1 ELSE 0 END), 0) || '/' || COUNT(1) FROM TB_LMS_EXAM_BSC AA JOIN TB_LMS_EXAM_CRE_CRS_RLTN BB ON AA.EXAM_ID = BB.EXAM_ID AND BB.DELYN = 'N' JOIN TB_LMS_EXAM_STARE CC ON AA.EXAM_ID = CC.EXAM_ID AND CC.STARE_CNT > 0 AND CC.DELYN = 'N' WHERE BB.SBJCT_ID = A.SBJCT_ID AND CC.STD_ID IN (SELECT STD_ID FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = A.SBJCT_ID AND ATNDLC_STSCD = 'S' AND AUDITYN = 'N') AND AA.DELYN = 'N' AND AA.USEYN = 'Y' AND AA.EXAM_QSTNS_CMPTNYN = 'Y' AND AA.EXAM_CTGRCD = 'EXAM' AND AA.TKEXAM_TYCD = 'A' ) AS AEXAM_CNT , NVL((SELECT MRK_RFLTRT FROM TB_LMS_STD_SCORE_ITEM_CONF WHERE MRK_TYCD = 'MIDDLE_TEST' AND SBJCT_ID = A.SBJCT_ID AND ROWNUM = 1), 0) AS MID_EXAM_SCORE_RATIO , B.EXAM_TYCD AS MID_EXAM_TYPE_CD , B.EXAM_TTL AS MID_EXAM_TITLE , B.EXAM_SDTTM AS MID_EXAM_START_DTTM , B.TKEXAM_MNTS AS MID_EXAM_STARE_TM , B.MRK_OYN AS MID_SCORE_OPEN_YN , B.EXAMPPR_OYN AS MID_GRADE_VIEW_YN , B.EXAM_SBST_REF_ID AS MID_INS_REF_CD , CASE WHEN B.EXAM_TYCD = 'QUIZ' THEN ( SELECT NVL(SUM(CASE WHEN BB.EVLYN = 'Y' THEN 1 ELSE 0 END), 0) || '/' || COUNT(1) FROM TB_LMS_EXAM_BSC AA JOIN TB_LMS_EXAM_STARE BB ON AA.EXAM_ID = BB.EXAM_ID AND BB.STARE_CNT > 0 AND BB.DELYN = 'N' WHERE AA.EXAM_ID = B.EXAM_SBST_REF_ID AND BB.STD_ID IN (SELECT STD_ID FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = A.SBJCT_ID AND ATNDLC_STSCD = 'S' AND AUDITYN = 'N') ) WHEN B.EXAM_TYCD = 'ASMNT' THEN ( SELECT NVL(SUM(CASE WHEN BB.EVLYN = 'Y' THEN 1 ELSE 0 END), 0) || '/' || COUNT(1) FROM TB_LMS_ASMT AA JOIN TB_LMS_ASMT_SBMSN BB ON AA.ASMT_ID = BB.ASMT_ID AND BB.SBMSN_STSCD IN ('SUBMIT', 'RE', 'LATE') AND BB.DELYN = 'N' WHERE AA.ASMT_ID = B.EXAM_SBST_REF_ID AND BB.STD_ID IN (SELECT STD_ID FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = A.SBJCT_ID AND ATNDLC_STSCD = 'S' AND AUDITYN = 'N') ) WHEN B.EXAM_TYCD = 'FORUM' THEN ( SELECT NVL(SUM(CASE WHEN CC.EVLYN = 'Y' THEN 1 ELSE 0 END), 0) || '/' || COUNT(1) FROM TB_LMS_DSCS AA JOIN TB_LMS_ATNDLC_SBJCT BB ON AA.SBJCT_ID = BB.SBJCT_ID AND BB.ATNDLC_STSCD = 'S' AND BB.AUDITYN = 'N' AND ( EXISTS (SELECT 1 FROM TB_LMS_DSCS_ATCL WHERE DSCS_ID = AA.DSCS_ID AND STD_ID = BB.STD_ID AND DELYN = 'N') OR EXISTS (SELECT 1 FROM TB_LMS_DSCS_CMNT WHERE DSCS_ID = AA.DSCS_ID AND STD_ID = BB.STD_ID AND DELYN = 'N') ) LEFT JOIN TB_LMS_DSCS_PTCP CC ON AA.DSCS_ID = CC.DSCS_ID AND BB.STD_ID = CC.STD_ID AND CC.DELYN = 'N' AND CC.EVLYN = 'Y' WHERE AA.DSCS_ID = B.EXAM_SBST_REF_ID ) END AS MID_EXAM_CNT , NVL((SELECT MRK_RFLTRT FROM TB_LMS_STD_SCORE_ITEM_CONF WHERE MRK_TYCD = 'LAST_TEST' AND SBJCT_ID = A.SBJCT_ID AND ROWNUM = 1), 0) AS LAST_EXAM_SCORE_RATIO , C.EXAM_TYCD AS LAST_EXAM_TYPE_CD , C.EXAM_TTL AS LAST_EXAM_TITLE , C.EXAM_SDTTM AS LAST_EXAM_START_DTTM , C.TKEXAM_MNTS AS LAST_EXAM_STARE_TM , C.MRK_OYN AS LAST_SCORE_OPEN_YN , C.EXAMPPR_OYN AS LAST_GRADE_VIEW_YN , C.EXAM_SBST_REF_ID AS LAST_INS_REF_CD , CASE WHEN C.EXAM_TYCD = 'QUIZ' THEN ( SELECT NVL(SUM(CASE WHEN BB.EVLYN = 'Y' THEN 1 ELSE 0 END), 0) || '/' || COUNT(1) FROM TB_LMS_EXAM_BSC AA JOIN TB_LMS_EXAM_STARE BB ON AA.EXAM_ID = BB.EXAM_ID AND BB.STARE_CNT > 0 AND BB.DELYN = 'N' WHERE AA.EXAM_ID = C.EXAM_SBST_REF_ID AND BB.STD_ID IN (SELECT STD_ID FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = A.SBJCT_ID AND ATNDLC_STSCD = 'S' AND AUDITYN = 'N') ) WHEN C.EXAM_TYCD = 'ASMNT' THEN ( SELECT NVL(SUM(CASE WHEN BB.EVLYN = 'Y' THEN 1 ELSE 0 END), 0) || '/' || COUNT(1) FROM TB_LMS_ASMT AA JOIN TB_LMS_ASMT_SBMSN BB ON AA.ASMT_ID = BB.ASMT_ID AND BB.SBMSN_STSCD IN ('SUBMIT', 'RE', 'LATE') AND BB.DELYN = 'N' WHERE AA.ASMT_ID = C.EXAM_SBST_REF_ID AND BB.STD_ID IN (SELECT STD_ID FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = A.SBJCT_ID AND ATNDLC_STSCD = 'S' AND AUDITYN = 'N') ) WHEN C.EXAM_TYCD = 'FORUM' THEN ( SELECT NVL(SUM(CASE WHEN CC.EVLYN = 'Y' THEN 1 ELSE 0 END), 0) || '/' || COUNT(1) FROM TB_LMS_DSCS AA JOIN TB_LMS_ATNDLC_SBJCT BB ON AA.SBJCT_ID = BB.SBJCT_ID AND BB.ATNDLC_STSCD = 'S' AND BB.AUDITYN = 'N' AND ( EXISTS (SELECT 1 FROM TB_LMS_DSCS_ATCL WHERE DSCS_ID = AA.DSCS_ID AND STD_ID = BB.STD_ID AND DELYN = 'N') OR EXISTS (SELECT 1 FROM TB_LMS_DSCS_CMNT WHERE DSCS_ID = AA.DSCS_ID AND STD_ID = BB.STD_ID AND DELYN = 'N') ) LEFT JOIN TB_LMS_DSCS_PTCP CC ON AA.DSCS_ID = CC.DSCS_ID AND BB.STD_ID = CC.STD_ID AND CC.DELYN = 'N' AND CC.EVLYN = 'Y' WHERE AA.DSCS_ID = C.EXAM_SBST_REF_ID ) END AS LAST_EXAM_CNT FROM ( SELECT A.SBJCT_ID , A.UNIV_CD , A.UNIV_GBNCD , A.CRS_ID , A.SBJCT_ID , A.CRS_ID , A.SBJCTNM , (SELECT DEPTNM FROM TB_HOME_USER_DEPT_CD WHERE ORG_ID = #{orgId} AND DEPT_CD = A.DEPT_CD) AS DEPTNM , A.DVCLAS_NO , C.USER_ID , D.DEPT_CD_ODR , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = C.USER_ID) AS USERNM , (SELECT USER_ID FROM SBJCT_PROF WHERE SBJCT_ID = A.SBJCT_ID AND PROF_TYCD = 'ASSISTANT' AND ROWNUM = 1) AS ASSIST_NO FROM TB_LMS_SBJCT A JOIN TB_LMS_TERM_CRE_CRS_RLTN B ON A.SBJCT_ID = B.SBJCT_ID AND B.CRS_SMSTR_ID = ( SELECT CRS_SMSTR_ID FROM CRS_SMSTR WHERE ORG_ID = #{orgId} AND DGRS_YR = #{haksaYear} AND DGRS_SMSTR = #{haksaTerm} ) JOIN TB_HOME_USER_DEPT_CD D ON A.DEPT_CD = D.DEPT_CD AND ORG_ID = #{orgId} LEFT JOIN SBJCT_PROF C ON A.SBJCT_ID = C.SBJCT_ID AND C.PROF_TYCD = 'PROFESSOR' AND C.RPRSYN = 'Y' WHERE A.DELYN = 'N' AND A.USEYN = 'Y' AND A.SBJCT_TYCD = 'UNI'
AND A.SBJCT_ID = #{crsCreCd}
AND A.UNIV_CD = #{uniCd}
AND A.UNIV_GBNCD = #{univGbn}
AND A.DEPT_CD = #{deptId}
AND ( LOWER(A.CRS_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.SBJCTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER((SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = C.USER_ID)) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
) A LEFT JOIN ( SELECT A.EXAM_ID , A.EXAM_TYCD , A.EXAM_TTL , A.EXAM_SDTTM , A.TKEXAM_MNTS , A.MRK_OYN , A.EXAMPPR_OYN , A.EXAM_SBST_REF_ID , B.SBJCT_ID FROM TB_LMS_EXAM_BSC A JOIN TB_LMS_EXAM_CRE_CRS_RLTN B ON A.EXAM_ID = B.EXAM_ID AND B.DELYN = 'N' WHERE A.DELYN = 'N' AND A.USEYN = 'Y' AND A.EXAM_CTGRCD = 'EXAM' AND A.TKEXAM_TYCD = 'M' ) B ON A.SBJCT_ID = B.SBJCT_ID LEFT JOIN ( SELECT A.EXAM_ID , A.EXAM_TYCD , A.EXAM_TTL , A.EXAM_SDTTM , A.TKEXAM_MNTS , A.MRK_OYN , A.EXAMPPR_OYN , A.EXAM_SBST_REF_ID , B.SBJCT_ID FROM TB_LMS_EXAM_BSC A JOIN TB_LMS_EXAM_CRE_CRS_RLTN B ON A.EXAM_ID = B.EXAM_ID AND B.DELYN = 'N' WHERE A.DELYN = 'N' AND A.USEYN = 'Y' AND A.EXAM_CTGRCD = 'EXAM' AND A.TKEXAM_TYCD = 'L' ) C ON A.SBJCT_ID = C.SBJCT_ID ORDER BY A.DEPT_CD_ODR, A.CRS_ID, A.DVCLAS_NO

/* SQL ID : DashboardDAO.listLessonStatusByStd 설 명 : 관리자 메인 > 학생별 학습현황 */ SELECT A.SBJCT_ID AS SBJCT_ID , MAX(A.SBJCTNM) AS SBJCTNM , A.STD_ID AS STD_ID , MAX(A.DVCLAS_NO) AS DVCLAS_NO , MAX(A.SCYR) AS SCYR , MAX(A.ENTR_YY) AS ENTR_YY , MAX(A.ENTR_HY) AS ENTR_HY , MAX(A.USERNM) AS USERNM , MAX(A.USER_ID) AS USER_ID , MAX(A.MOBILE_NO) AS MOBILE_NO , MAX(A.EMAIL) AS EMAIL , MAX(A.DEPTNM) AS DEPTNM , MAX(A.REP_USER_ID) AS REP_USER_ID , MAX(CASE WHEN A.LCTR_SCHDL_SEQ = 1 THEN A.ATNDLC_STSCD ELSE NULL END) AS STUDY_STATUS_CD1 , MAX(CASE WHEN A.LCTR_SCHDL_SEQ = 2 THEN A.ATNDLC_STSCD ELSE NULL END) AS STUDY_STATUS_CD2 , MAX(CASE WHEN A.LCTR_SCHDL_SEQ = 3 THEN A.ATNDLC_STSCD ELSE NULL END) AS STUDY_STATUS_CD3 , MAX(CASE WHEN A.LCTR_SCHDL_SEQ = 4 THEN A.ATNDLC_STSCD ELSE NULL END) AS STUDY_STATUS_CD4 , MAX(CASE WHEN A.LCTR_SCHDL_SEQ = 5 THEN A.ATNDLC_STSCD ELSE NULL END) AS STUDY_STATUS_CD5 , MAX(CASE WHEN A.LCTR_SCHDL_SEQ = 6 THEN A.ATNDLC_STSCD ELSE NULL END) AS STUDY_STATUS_CD6 , MAX(CASE WHEN A.LCTR_SCHDL_SEQ = 7 THEN A.ATNDLC_STSCD ELSE NULL END) AS STUDY_STATUS_CD7 , MAX(CASE WHEN A.LCTR_SCHDL_SEQ = 8 THEN A.ATNDLC_STSCD ELSE NULL END) AS STUDY_STATUS_CD8 , MAX(CASE WHEN A.LCTR_SCHDL_SEQ = 9 THEN A.ATNDLC_STSCD ELSE NULL END) AS STUDY_STATUS_CD9 , MAX(CASE WHEN A.LCTR_SCHDL_SEQ = 10 THEN A.ATNDLC_STSCD ELSE NULL END) AS STUDY_STATUS_CD10 , MAX(CASE WHEN A.LCTR_SCHDL_SEQ = 11 THEN A.ATNDLC_STSCD ELSE NULL END) AS STUDY_STATUS_CD11 , MAX(CASE WHEN A.LCTR_SCHDL_SEQ = 12 THEN A.ATNDLC_STSCD ELSE NULL END) AS STUDY_STATUS_CD12 , MAX(CASE WHEN A.LCTR_SCHDL_SEQ = 13 THEN A.ATNDLC_STSCD ELSE NULL END) AS STUDY_STATUS_CD13 , MAX(CASE WHEN A.LCTR_SCHDL_SEQ = 14 THEN A.ATNDLC_STSCD ELSE NULL END) AS STUDY_STATUS_CD14 , MAX(CASE WHEN A.LCTR_SCHDL_SEQ = 15 THEN A.ATNDLC_STSCD ELSE NULL END) AS STUDY_STATUS_CD15
, CASE WHEN SUM(LESSON_START_CNT) = 0 THEN 0 ELSE CASE WHEN FLOOR(SUM(CASE WHEN A.ATNDLC_STSCD IN ('COMPLETE', 'LATE') THEN 1 ELSE 0 END) / SUM(LESSON_START_CNT) * 100) > 100 THEN 100 ELSE FLOOR(SUM(CASE WHEN A.ATNDLC_STSCD IN ('COMPLETE', 'LATE') THEN 1 ELSE 0 END) / SUM(LESSON_START_CNT) * 100) END END AS STUDY_RATE
, ( SELECT SUM( CASE WHEN AA.EXAM_TYCD IN ('EXAM', 'QUIZ') THEN (CASE WHEN CC.STARE_CNT > 0 THEN 1 ELSE 0 END) WHEN AA.EXAM_TYCD = 'ASMNT' THEN ( SELECT 1 FROM TB_LMS_ASMT_SBMSN WHERE ASMT_ID = AA.EXAM_SBST_REF_ID AND STD_ID = A.STD_ID AND DELYN = 'N' AND SBMSN_STSCD IN ('SUBMIT', 'RE', 'LATE') ) WHEN AA.EXAM_TYCD = 'FORUM' THEN ( SELECT 1 FROM TB_LMS_DSCS AAA WHERE AAA.DSCS_ID = AA.EXAM_SBST_REF_ID AND ( EXISTS (SELECT 1 FROM TB_LMS_DSCS_ATCL WHERE DSCS_ID = AAA.DSCS_ID AND STD_ID = A.STD_ID AND DELYN = 'N') OR EXISTS (SELECT 1 FROM TB_LMS_DSCS_CMNT WHERE DSCS_ID = AAA.DSCS_ID AND STD_ID = A.STD_ID AND DELYN = 'N') ) ) ELSE 0 END ) || '/' || COUNT(1) FROM TB_LMS_EXAM_BSC AA JOIN TB_LMS_EXAM_CRE_CRS_RLTN BB ON AA.EXAM_ID = BB.EXAM_ID AND BB.DELYN = 'N' LEFT JOIN TB_LMS_EXAM_STARE CC ON AA.EXAM_ID = CC.EXAM_ID AND CC.DELYN = 'N' WHERE AA.DELYN = 'N' AND BB.SBJCT_ID = A.SBJCT_ID AND CC.STD_ID = A.STD_ID AND AA.USEYN = 'Y' AND AA.EXAM_QSTNS_CMPTNYN = 'Y' AND AA.EXAM_CTGRCD = 'EXAM' AND AA.TKEXAM_TYCD IN('M', 'L') ) AS EXAM_CNT
, ( SELECT NVL(SUM(CASE WHEN EXISTS( SELECT 1 FROM TB_LMS_BBS_ATCL WHERE BBS_ID = CC.BBS_ID AND UP_ATCL_ID = CC.ATCL_ID AND CC.DELYN = 'N' )THEN 1 ELSE 0 END), 0) || '/' || COUNT(1) FROM TB_LMS_BBS AA JOIN TB_HOME_BBS_RLTN BB ON AA.BBS_ID = BB.BBS_ID AND BB.CONTS_TYCD = 'COURSE' JOIN TB_LMS_BBS_ATCL CC ON AA.BBS_ID = CC.BBS_ID AND CC.DELYN = 'N' AND CC.UP_ATCL_ID IS NULL WHERE AA.DELYN = 'N' AND BB.RLTN_REF_CD = A.SBJCT_ID AND AA.SYS_BSC_PVSNYN = 'Y' AND CC.RGTR_ID = A.USER_ID AND AA.BBS_ID = 'QNA' ) AS QNA_CNT
, ( SELECT NVL(SUM(CASE WHEN EXISTS( SELECT 1 FROM TB_LMS_BBS_ATCL WHERE BBS_ID = CC.BBS_ID AND UP_ATCL_ID = CC.ATCL_ID AND CC.DELYN = 'N' ) THEN 1 ELSE 0 END), 0) || '/' || COUNT(1) FROM TB_LMS_BBS AA JOIN TB_HOME_BBS_RLTN BB ON AA.BBS_ID = BB.BBS_ID AND BB.CONTS_TYCD = 'COURSE' JOIN TB_LMS_BBS_ATCL CC ON AA.BBS_ID = CC.BBS_ID AND CC.DELYN = 'N' AND CC.UP_ATCL_ID IS NULL WHERE AA.DELYN = 'N' AND BB.RLTN_REF_CD = A.SBJCT_ID AND CC.RGTR_ID = A.USER_ID AND AA.SYS_BSC_PVSNYN = 'Y' AND AA.BBS_ID = 'SECRET' ) AS SECRET_CNT
, ( SELECT COUNT(BB.ASMT_SBMSN_ID) || '/' || COUNT(1) FROM TB_LMS_ASMT AA LEFT JOIN TB_LMS_ASMT_SBMSN BB ON AA.ASMT_ID = BB.ASMT_ID AND BB.SBMSN_STSCD IN ('SUBMIT', 'RE', 'LATE') AND BB.DELYN = 'N' WHERE AA.DELYN = 'N' AND BB.STD_ID = A.STD_ID AND AA.SBJCT_ID = A.SBJCT_ID AND ( AA.IND_YN = 'N' OR (AA.IND_YN = 'Y' AND BB.ASMT_SBMSN_ID IS NOT NULL) ) AND NOT EXISTS (SELECT 1 FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = AA.ASMT_ID) AND FN_DTTM() >= AA.SEND_START_DTTM ) AS ASMNT_CNT
, ( SELECT NVL(SUM(CASE WHEN EXISTS (SELECT 1 FROM TB_LMS_DSCS_ATCL WHERE DSCS_ID = AA.DSCS_ID AND STD_ID = A.STD_ID AND DELYN = 'N') OR EXISTS (SELECT 1 FROM TB_LMS_DSCS_CMNT WHERE DSCS_ID = AA.DSCS_ID AND STD_ID = A.STD_ID AND DELYN = 'N') THEN 1 ELSE 0 END), 0) || '/' || COUNT(1) FROM TB_LMS_DSCS AA WHERE AA.DELYN = 'N' AND AA.SBJCT_ID = A.SBJCT_ID AND NOT EXISTS (SELECT 1 FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = AA.DSCS_ID) AND FN_DTTM() >= AA.DSCS_SDTTM ) AS FORUM_CNT
, ( SELECT COUNT(CC.STD_ID) || '/' || COUNT(1) FROM TB_LMS_EXAM_BSC AA JOIN TB_LMS_EXAM_CRE_CRS_RLTN BB ON AA.EXAM_ID = BB.EXAM_ID AND BB.DELYN = 'N' LEFT JOIN TB_LMS_EXAM_STARE CC ON AA.EXAM_ID = CC.EXAM_ID AND CC.STARE_CNT > 0 AND CC.DELYN = 'N' WHERE AA.DELYN = 'N' AND BB.SBJCT_ID = A.SBJCT_ID AND CC.STD_ID = A.STD_ID AND AA.USEYN = 'Y' AND AA.EXAM_QSTNS_CMPTNYN IN ('Y', 'M') AND AA.EXAM_CTGRCD = 'QUIZ' AND AA.TKEXAM_TYCD = 'A' AND FN_DTTM() >= AA.EXAM_SDTTM ) AS QUIZ_CNT
, ( SELECT COUNT(CC.SRVY_ID) || '/' || COUNT(1) FROM TB_LMS_SRVY AA JOIN TB_LMS_RESCH_CRE_CRS_RLTN BB ON AA.SRVY_ID = BB.SRVY_ID AND BB.DELYN = 'N' LEFT JOIN TB_LMS_SRVY_PTCP CC ON AA.SRVY_ID = CC.SRVY_ID AND EXISTS(SELECT 1 FROM TB_LMS_SRVY_RSPNS WHERE USER_ID = CC.USER_ID AND SRVY_ID = CC.SRVY_ID) WHERE AA.DELYN = 'N' AND BB.SBJCT_ID = A.SBJCT_ID AND CC.STD_ID = A.STD_ID AND CC.USER_ID = A.USER_ID AND AA.USEYN = 'Y' AND AA.SRVY_QSTNS_CMPTNYN = 'Y' AND FN_DTTM() >= AA.SRVY_SDTTM ) AS RESCH_CNT
, ( SELECT COUNT(CC.EXAM_ID) || '/' || COUNT(1) FROM TB_LMS_EXAM_BSC AA JOIN TB_LMS_EXAM_CRE_CRS_RLTN BB ON AA.EXAM_ID = BB.EXAM_ID AND BB.DELYN = 'N' LEFT JOIN TB_LMS_EXAM_STARE CC ON AA.EXAM_ID = CC.EXAM_ID AND CC.STARE_CNT > 0 AND CC.DELYN = 'N' WHERE AA.DELYN = 'N' AND BB.SBJCT_ID = A.SBJCT_ID AND CC.STD_ID = A.STD_ID AND AA.USEYN = 'Y' AND AA.EXAM_QSTNS_CMPTNYN = 'Y' AND AA.EXAM_CTGRCD = 'EXAM' AND AA.TKEXAM_TYCD = 'A' AND FN_DTTM() >= AA.EXAM_SDTTM ) AS AEXAM_CNT
, ( SELECT NVL(SUM(CASE WHEN BB.ATND_STSCD IN ('ATTEND', 'LATE')THEN 1 ELSE 0 END), 0) || '/' || COUNT(1) FROM TB_LMS_SMNR AA LEFT JOIN TB_LMS_SMNR_ATND BB ON AA.SMNR_ID = BB.SMNR_ID WHERE AA.DELYN = 'N' AND BB.USER_ID = A.USER_ID AND BB.STD_ID = A.STD_ID AND AA.SBJCT_ID = A.SBJCT_ID AND FN_DTTM() >= AA.SMNR_SDTTM ) AS SEMINAR_CNT FROM ( SELECT A.SBJCT_ID , A.SBJCTNM , A.DVCLAS_NO , A.REP_USER_ID , A.STD_ID , A.SCYR , A.ENTR_YY , A.ENTR_HY , A.USERNM , A.USER_ID , A.MOBILE_NO , A.EMAIL , A.DEPTNM , B.LCTR_SCHDL_SEQ , B.LCTR_WKNO_GBNCD , CASE WHEN FN_DT() >= NVL(B.LCTR_RCG_SYMD, B.LCTR_SYMD) THEN 1 ELSE 0 END AS LESSON_START_CNT , CASE
WHEN C.ATNDLC_STSCD IN ('COMPLETE', 'LATE') THEN C.ATNDLC_STSCD
WHEN FN_DT() < NVL(B.LCTR_RCG_SYMD, B.LCTR_SYMD) THEN 'READY'
WHEN FN_DT() BETWEEN NVL(B.LCTR_RCG_SYMD, B.LCTR_SYMD) AND NVL(B.LCTR_RCG_EYMD, B.LCTR_EYMD) THEN 'STUDY'
WHEN FN_DT() > NVL(B.LCTR_RCG_EYMD, B.LCTR_EYMD) THEN 'NOSTUDY' END AS ATNDLC_STSCD FROM ( SELECT A.SBJCT_ID , A.SBJCTNM , A.DVCLAS_NO , (SELECT USER_ID FROM SBJCT_PROF WHERE SBJCT_ID = A.SBJCT_ID AND PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y') AS REP_USER_ID , B.STD_ID , B.SCYR , C.ENTR_YY , C.ENTR_HY , C.USERNM , C.USER_ID , C.MOBILE_NO , C.EMAIL , (SELECT DEPTNM FROM TB_HOME_USER_DEPT_CD WHERE ORG_ID = #{orgId} AND DEPT_CD = C.DEPT_CD) AS DEPTNM FROM TB_LMS_SBJCT A JOIN TB_LMS_ATNDLC_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND B.ATNDLC_STSCD = 'S' JOIN TB_LMS_USR C ON B.USER_ID = C.USER_ID WHERE A.DELYN ='N' AND A.SBJCT_ID = #{haksaYear} AND A.CRS_ID = #{haksaTerm}
AND B.USER_ID = #{userId}
AND A.SBJCT_ID = #{crsCreCd}
AND A.UNIV_CD = #{uniCd}
AND A.UNIV_GBNCD = #{univGbn}
AND A.DEPT_CD = #{deptCd}
AND ( LOWER(C.USER_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(C.USERNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
) A LEFT JOIN TB_LMS_SBJCT_LCTR_SCHDL B ON A.SBJCT_ID = B.SBJCT_ID AND B.DELYN = 'N' AND ( B.LCTR_WKNO_GBNCD IN ('02', '03') OR EXISTS ( SELECT 1 FROM TB_LMS_SBJCT_LCTR_CONTS AA WHERE AA.LCTR_SCHDL_ID = B.LCTR_SCHDL_ID AND ( AA.LCTR_CONTS_GBNCD = 'VIDEO' OR ( AA.LCTR_CONTS_GBNCD = 'VIDEO_LINK' AND EXISTS (SELECT 1 FROM SBJCT_LCTR_CONTS_PAGE WHERE SBJCT_LCTR_CONTS_ID = AA.SBJCT_LCTR_CONTS_ID) ) ) AND AA.DELYN = 'N' AND AA.PRG_RFLTYN = 'Y' ) ) LEFT JOIN TB_LMS_LESSON_STUDY_STATE C ON B.LCTR_SCHDL_ID = C.LCTR_SCHDL_ID AND A.STD_ID = C.STD_ID ) A GROUP BY A.SBJCT_ID, A.STD_ID, A.USER_ID ORDER BY MAX(A.USERNM), MAX(A.USER_ID)

mapper.sql:
SELECT A.USER_ID , A.USERNM , A.MOBILE_NO , A.EMAIL , A.DEPT_CD , (SELECT DEPTNM FROM TB_HOME_USER_DEPT_CD WHERE ORG_ID = A.ORG_ID AND DEPT_CD = A.DEPT_CD AND USEYN = 'Y') AS DEPTNM , A.USER_GRADE , A.SCHREG_GBN , C.USER_AUTHRT_ID , CASE WHEN C.USER_AUTHRT_ID = 'SUP' THEN '슈퍼관리자' WHEN C.USER_AUTHRT_ID = 'MANAGER' THEN '관리자' WHEN C.USER_AUTHRT_ID = 'ADM' THEN '전체운영자' WHEN C.USER_AUTHRT_ID = 'CMG' THEN '과목운영자' WHEN C.USER_AUTHRT_ID = 'DEV' THEN '시스템운영자' WHEN C.USER_AUTHRT_ID = 'DGN' THEN '과목개설자' WHEN C.USER_AUTHRT_ID = 'MMG' THEN '공동운영자' WHEN C.USER_AUTHRT_ID = 'PFS' THEN '교수' WHEN C.USER_AUTHRT_ID = 'PROFESSOR' THEN '교수자' WHEN C.USER_AUTHRT_ID = 'TUT' THEN '조교' WHEN C.USER_AUTHRT_ID = 'ASSISTANT' THEN '조교' WHEN C.USER_AUTHRT_ID = 'ASSOCIATE' THEN '공동교수' WHEN C.USER_AUTHRT_ID = 'LEARNER' THEN '학습자' WHEN C.USER_AUTHRT_ID = 'USR' THEN '사용자' WHEN C.USER_AUTHRT_ID = 'MEMBER' THEN '회원' WHEN C.USER_AUTHRT_ID = 'OBS' THEN '관찰자' WHEN C.USER_AUTHRT_ID = 'GST' THEN '비인가자' ELSE '' END AUTHRT_GRPNM
, (SELECT KNOU_USER_ID FROM TB_HOME_USER_ORG_RLTN WHERE USER_ID = A.USER_ID) AS KNOU_USER_ID , (SELECT BB.USERNM FROM TB_HOME_USER_ORG_RLTN AA, USR BB WHERE AA.KNOU_USER_ID = BB.USER_ID AND AA.USER_ID = A.USER_ID) AS KNOU_USER_NM
FROM TB_LMS_USR A INNER JOIN TB_LMS_USER_ACNT B ON A.USER_ID = B.USER_ID INNER JOIN TB_LMS_USER_AUTHRT C ON A.USER_ID = C.USER_ID , (SELECT B.USER_ID FROM TB_LMS_TERM_CRE_CRS_RLTN A INNER JOIN TB_LMS_ATNDLC_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID WHERE 1 = 1
AND A.CRS_SMSTR_ID = #{termCd}
AND A.CRS_SMSTR_ID = (SELECT CRS_SMSTR_ID FROM CRS_SMSTR WHERE ORG_ID = #{orgId} AND DGRS_YR = #{haksaYear} AND DGRS_SMSTR = #{haksaTerm})
UNION SELECT B.USER_ID FROM TB_LMS_TERM_CRE_CRS_RLTN A INNER JOIN SBJCT_PROF B ON A.SBJCT_ID = B.SBJCT_ID WHERE 1 = 1
AND A.CRS_SMSTR_ID = #{termCd}
AND A.CRS_SMSTR_ID = (SELECT CRS_SMSTR_ID FROM CRS_SMSTR WHERE ORG_ID = #{orgId} AND DGRS_YR = #{haksaYear} AND DGRS_SMSTR = #{haksaTerm})
) E WHERE A.USER_ID = E.USER_ID
AND A.ORG_ID = #{orgId}
AND A.DEPT_CD = #{deptCd}
AND ( LOWER(A.USER_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.USERNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )

